async function viewUserPublicProfile(user) {
  if (!user || !user.id) return;
  // Build modal if missing
  let modal = document.getElementById("user-profile-viewer-modal");
  if (!modal) {
    modal = document.createElement("div");
    modal.id = "user-profile-viewer-modal";
    modal.setAttribute("role", "dialog");
    modal.setAttribute("aria-modal", "true");
    modal.style.cssText = "position:fixed;inset:0;background:rgba(8,12,20,0.78);z-index:10000;display:flex;align-items:flex-start;justify-content:center;padding:40px 16px;overflow-y:auto;backdrop-filter:blur(6px);";
    modal.innerHTML = `
      <div style="background:#0f172a;color:#e2e8f0;border-radius:18px;max-width:640px;width:100%;padding:0;box-shadow:0 20px 60px rgba(0,0,0,0.5);border:1px solid rgba(148,163,184,0.15);overflow:hidden;">
        <div style="display:flex;align-items:center;justify-content:space-between;padding:14px 18px;border-bottom:1px solid rgba(148,163,184,0.12);">
          <strong style="font-size:14px;letter-spacing:.02em;color:#94a3b8;">athlet.</strong>
          <button type="button" id="upv-close" aria-label="Schließen" style="background:transparent;border:none;color:#94a3b8;font-size:24px;line-height:1;cursor:pointer;padding:4px 8px;">×</button>
        </div>
        <div id="upv-body" style="padding:22px;"></div>
      </div>`;
    document.body.appendChild(modal);
    modal.addEventListener("click", (e) => { if (e.target === modal) closeUserProfileViewer(); });
    modal.querySelector("#upv-close").addEventListener("click", closeUserProfileViewer);
    document.addEventListener("keydown", (e) => {
      if (e.key === "Escape" && document.getElementById("user-profile-viewer-modal")?.style.display !== "none") closeUserProfileViewer();
    });
  }
  modal.style.display = "flex";
  document.body.style.overflow = "hidden";

  const body = modal.querySelector("#upv-body");
  const name = user.display_name || (user.email ? user.email.split("@")[0] : "Athlet");
  const avatarHtml = user.profile_image
    ? `<img src="${escapeHtml(user.profile_image)}" alt="" style="width:84px;height:84px;border-radius:50%;object-fit:cover;border:2px solid rgba(148,163,184,0.2);">`
    : `<div style="width:84px;height:84px;border-radius:50%;background:linear-gradient(135deg,#3b82f6,#8b5cf6);display:flex;align-items:center;justify-content:center;color:#fff;font-weight:700;font-size:32px;">${escapeHtml((name.charAt(0) || "?").toUpperCase())}</div>`;

  body.innerHTML = `
    <div style="display:flex;gap:18px;align-items:center;margin-bottom:20px;">
      ${avatarHtml}
      <div style="flex:1;min-width:0;">
        <div style="font-size:22px;font-weight:700;color:#f1f5f9;">${escapeHtml(name)}</div>
        <div style="font-size:12px;color:#64748b;margin-top:2px;">${escapeHtml(user.email || "")}</div>
      </div>
    </div>
    <div id="upv-stats" style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:18px;">
      <div style="background:rgba(148,163,184,0.06);border-radius:10px;padding:12px;text-align:center;"><div style="font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:.06em;">Aktivitäten</div><div id="upv-s-count" style="font-size:20px;font-weight:700;margin-top:4px;">…</div></div>
      <div style="background:rgba(148,163,184,0.06);border-radius:10px;padding:12px;text-align:center;"><div style="font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:.06em;">Distanz</div><div id="upv-s-dist" style="font-size:20px;font-weight:700;margin-top:4px;">…</div></div>
      <div style="background:rgba(148,163,184,0.06);border-radius:10px;padding:12px;text-align:center;"><div style="font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:.06em;">Zeit</div><div id="upv-s-time" style="font-size:20px;font-weight:700;margin-top:4px;">…</div></div>
    </div>
    <div style="font-size:12px;color:#94a3b8;text-transform:uppercase;letter-spacing:.08em;margin-bottom:8px;">Zuletzt</div>
    <div id="upv-activities" style="display:flex;flex-direction:column;gap:8px;"><div style="color:#64748b;font-size:13px;">Lade …</div></div>`;

  // Fetch public activities for this user
  try {
    const acts = window.sbDb?.getActivities ? await window.sbDb.getActivities(user.id, 50) : [];
    const count = acts.length;
    const distKm = acts.reduce((s, a) => s + Number(a.distance_km || 0), 0);
    const timeSec = acts.reduce((s, a) => s + Number(a.moving_time_sec || 0), 0);
    const hours = Math.floor(timeSec / 3600);
    const mins = Math.floor((timeSec % 3600) / 60);
    document.getElementById("upv-s-count").textContent = count.toLocaleString("de-DE");
    document.getElementById("upv-s-dist").textContent = `${distKm.toFixed(0)} km`;
    document.getElementById("upv-s-time").textContent = hours > 0 ? `${hours}h ${mins}m` : `${mins}m`;

    const list = document.getElementById("upv-activities");
    if (!count) {
      list.innerHTML = `<div style="color:#64748b;font-size:13px;">Keine öffentlichen Aktivitäten.</div>`;
    } else {
      const sportEmoji = (s) => {
        const t = String(s || "").toLowerCase();
        if (t.includes("run")) return "🏃";
        if (t.includes("bike") || t.includes("ride")) return "🚴";
        if (t.includes("swim")) return "🏊";
        return "💪";
      };
      list.innerHTML = acts.slice(0, 10).map((a) => {
        const d = a.created_at ? new Date(a.created_at).toLocaleDateString("de-DE", { day: "2-digit", month: "short", year: "numeric" }) : "";
        const km = Number(a.distance_km || 0).toFixed(1);
        const t = Number(a.moving_time_sec || 0);
        const tStr = t ? `${Math.floor(t/3600) ? Math.floor(t/3600)+"h " : ""}${Math.floor((t%3600)/60)}m` : "";
        return `<div style="display:flex;gap:10px;align-items:center;padding:10px;background:rgba(148,163,184,0.04);border-radius:8px;"><span style="font-size:20px;">${sportEmoji(a.sport_type)}</span><div style="flex:1;min-width:0;"><div style="font-weight:600;font-size:13px;color:#e2e8f0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${escapeHtml(a.title || "Aktivität")}</div><div style="font-size:11px;color:#64748b;">${d}</div></div><div style="text-align:right;font-size:12px;color:#cbd5e1;"><div>${km} km</div>${tStr ? `<div style="color:#64748b;">${tStr}</div>` : ""}</div></div>`;
      }).join("");
    }
  } catch (e) {
    console.warn("[viewUserPublicProfile] fetch failed:", e?.message || e);
    document.getElementById("upv-activities").innerHTML = `<div style="color:#ef4444;font-size:13px;">Fehler beim Laden.</div>`;
    document.getElementById("upv-s-count").textContent = "–";
    document.getElementById("upv-s-dist").textContent = "–";
    document.getElementById("upv-s-time").textContent = "–";
  }
}

function closeUserProfileViewer() {
  const modal = document.getElementById("user-profile-viewer-modal");
  if (modal) modal.style.display = "none";
  document.body.style.overflow = "";
}
window.viewUserPublicProfile = viewUserPublicProfile;

// ═══════════════════════════════════════════════════════════════════════════
//  NOTIFICATION SYSTEM
//  In-app notifications stored in Supabase + local cache.
//  Types: activity_new, pr_new, props_received, comment, friend_request,
//         medal_earned, sync_complete, plan_ready
// ═══════════════════════════════════════════════════════════════════════════
const _notifState = { items: [], unreadCount: 0, isOpen: false, lastFetched: 0 };

const NOTIF_ICONS = {
  activity_new: '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#aaf57c" stroke-width="2"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>',
  pr_new: '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#e5a93d" stroke-width="2"><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/></svg>',
  props_received: '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#f472b6" stroke-width="2"><path d="M14 9V5a3 3 0 0 0-3-3l-4 9v11h11.28a2 2 0 0 0 2-1.7l1.38-9a2 2 0 0 0-2-2.3zM7 22H4a2 2 0 0 1-2-2v-7a2 2 0 0 1 2-2h3"/></svg>',
  comment: '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#86d7ff" stroke-width="2"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>',
  friend_request: '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#d0b2ff" stroke-width="2"><path d="M16 21v-2a4 4 0 00-4-4H5a4 4 0 00-4 4v2"/><circle cx="8.5" cy="7" r="4"/><line x1="20" y1="8" x2="20" y2="14"/><line x1="23" y1="11" x2="17" y2="11"/></svg>',
  medal_earned: '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#e5a93d" stroke-width="2"><circle cx="12" cy="8" r="7"/><polyline points="8.21 13.89 7 23 12 20 17 23 15.79 13.88"/></svg>',
  sync_complete: '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#22c55e" stroke-width="2"><polyline points="20 6 9 17 4 12"/></svg>',
  plan_ready: '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#3b82f6" stroke-width="2"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>',
  default: '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#94a3b8" stroke-width="2"><circle cx="12" cy="12" r="10"/><line x1="12" y1="16" x2="12" y2="12"/><line x1="12" y1="8" x2="12.01" y2="8"/></svg>',
};

function addNotification(type, title, body, meta = {}) {
  const notif = {
    id: crypto.randomUUID?.() || `n-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
    type: type || "default",
    title: title || "",
    body: body || "",
    time: new Date().toISOString(),
    read: false,
    ...meta,
  };
  _notifState.items.unshift(notif);
  // Cap at 50
  if (_notifState.items.length > 50) _notifState.items = _notifState.items.slice(0, 50);
  _notifState.unreadCount = _notifState.items.filter((n) => !n.read).length;
  _persistNotifications();
  _renderNotifBadge();
  _renderNotifList();
  return notif;
}

function _persistNotifications() {
  const account = getCurrentAccount?.();
  if (!account) return;
  if (!account._notifications) account._notifications = [];
  account._notifications = _notifState.items.slice(0, 50);
  persistStore();
}

function _loadNotifications() {
  const account = getCurrentAccount?.();
  if (!account) return;
  _notifState.items = Array.isArray(account._notifications) ? account._notifications : [];
  _notifState.unreadCount = _notifState.items.filter((n) => !n.read).length;
  _renderNotifBadge();
}

function _renderNotifBadge() {
  const bellBtn = document.getElementById("notif-bell-btn");
  const badge = document.getElementById("notif-bell-badge");
  if (!bellBtn) return;
  const account = getCurrentAccount?.();
  bellBtn.hidden = !account;
  if (badge) {
    const count = _notifState.unreadCount;
    badge.textContent = count > 9 ? "9+" : String(count);
    badge.hidden = count === 0;
  }
  bellBtn.classList.toggle("has-unread", _notifState.unreadCount > 0);
}

function _renderNotifList() {
  const list = document.getElementById("notif-list");
  if (!list) return;
  if (!_notifState.items.length) {
    list.innerHTML = '<div class="notif-empty">Keine neuen Benachrichtigungen</div>';
    return;
  }
  list.innerHTML = _notifState.items.slice(0, 30).map((n) => {
    const icon = NOTIF_ICONS[n.type] || NOTIF_ICONS.default;
    const timeAgo = _timeAgo(n.time);
    const unread = n.read ? "" : " is-unread";
    return `<div class="notif-item${unread}" data-notif-id="${n.id}">
      <div class="notif-item-icon">${icon}</div>
      <div class="notif-item-content">
        <div class="notif-item-title">${escapeHtml(n.title)}</div>
        ${n.body ? `<div class="notif-item-body">${escapeHtml(n.body)}</div>` : ""}
      </div>
      <div class="notif-item-time">${timeAgo}</div>
    </div>`;
  }).join("");
}

function _timeAgo(iso) {
  const diff = (Date.now() - new Date(iso).getTime()) / 1000;
  if (diff < 60) return "jetzt";
  if (diff < 3600) return `${Math.floor(diff / 60)}m`;
  if (diff < 86400) return `${Math.floor(diff / 3600)}h`;
  if (diff < 604800) return `${Math.floor(diff / 86400)}d`;
  return new Date(iso).toLocaleDateString("de-DE", { day: "numeric", month: "short" });
}

function _toggleNotifDropdown() {
  const dd = document.getElementById("notif-dropdown");
  if (!dd) return;
  _notifState.isOpen = !_notifState.isOpen;
  dd.classList.toggle("is-open", _notifState.isOpen);
  if (_notifState.isOpen) _renderNotifList();
}

function _markAllNotificationsRead() {
  _notifState.items.forEach((n) => { n.read = true; });
  _notifState.unreadCount = 0;
  _persistNotifications();
  _renderNotifBadge();
  _renderNotifList();
}

// Wire notification UI
document.getElementById("notif-bell-btn")?.addEventListener("click", (e) => {
  e.stopPropagation();
  _toggleNotifDropdown();
});
document.getElementById("notif-mark-read-btn")?.addEventListener("click", () => _markAllNotificationsRead());
document.addEventListener("click", (e) => {
  if (_notifState.isOpen && !e.target.closest(".notif-dropdown") && !e.target.closest("#notif-bell-btn")) {
    _notifState.isOpen = false;
    document.getElementById("notif-dropdown")?.classList.remove("is-open");
  }
});
// Click on individual notification marks it read
document.getElementById("notif-list")?.addEventListener("click", (e) => {
  const item = e.target.closest(".notif-item");
  if (!item) return;
  const id = item.dataset.notifId;
  const notif = _notifState.items.find((n) => n.id === id);
  if (notif && !notif.read) {
    notif.read = true;
    _notifState.unreadCount = Math.max(0, _notifState.unreadCount - 1);
    item.classList.remove("is-unread");
    _persistNotifications();
    _renderNotifBadge();
  }
});

// Expose globally for use from other modules
window.addNotification = addNotification;

// ── Global: Click on athlete name/avatar → view their public profile ──
document.addEventListener("click", async (e) => {
  const el = e.target.closest("[data-view-profile]");
  if (!el) return;
  const email = el.dataset.viewProfile;
  if (!email) return;
  // Don't open own profile in modal
  const me = getCurrentAccount?.();
  if (me && me.email === email) return;
  // Look up user by email in Supabase
  try {
    if (window.sb) {
      const { data } = await sb.from("profiles").select("id,email,display_name,profile_image").eq("email", email).maybeSingle();
      if (data) { viewUserPublicProfile(data); return; }
    }
    // Fallback: local
    const local = (appStore.accounts || []).find((a) => a.email === email);
    if (local) viewUserPublicProfile({ id: local.id, email: local.email, display_name: resolveDisplayName(local), profile_image: local.profileImage });
  } catch (_) {}
});

// Home feed athlete search (Supabase-backed + local fallback)
let _homeSearchSeq = 0;
async function runHomeAthleteSearch(query) {
  const resultsEl = document.getElementById("home-athlete-search-results");
  if (!resultsEl) return;
  const account = getCurrentAccount();
  if (!account) return;
  const q = String(query || "").trim();
  if (!q) {
    resultsEl.innerHTML = `<div class="empty-copy">Finde andere Athleten und connecte dich.</div>`;
    return;
  }
  resultsEl.innerHTML = `<div class="empty-copy">Suche …</div>`;
  const seq = ++_homeSearchSeq;

  // Supabase remote search via profiles_public view
  const remote = window.sbDb?.searchUsers
    ? await window.sbDb.searchUsers(q, 12).catch(() => [])
    : [];
  if (seq !== _homeSearchSeq) return;

  // Local fallback (offline / pre-Supabase users)
  const lo = q.toLowerCase();
  const local = (appStore?.accounts || [])
    .filter((a) => a.email !== account.email)
    .filter((a) => {
      const name = (a.email ? a.email.split("@")[0] : a.displayName || "Athlete").toLowerCase();
      const displayName = (a.displayName || "").toLowerCase();
      return name.includes(lo) || displayName.includes(lo) || a.email.toLowerCase().includes(lo);
    })
    .map((a) => ({ id: a.email, email: a.email, display_name: a.displayName || a.email.split("@")[0], profile_image: a.profileImage || null, _local: true }));

  // De-dup (remote wins) by email, exclude self
  const seen = new Set();
  const merged = [];
  remote.filter((r) => r.email && r.email !== account.email).forEach((r) => {
    if (seen.has(r.email)) return;
    seen.add(r.email); merged.push(r);
  });
  local.forEach((l) => { if (!seen.has(l.email)) { seen.add(l.email); merged.push(l); } });

  if (!merged.length) {
    resultsEl.innerHTML = `<div class="empty-copy">Keine Athleten gefunden.</div>`;
    return;
  }
  resultsEl.innerHTML = merged.slice(0, 12).map((u) => {
    const isConnected = Boolean(account.friends?.includes(u.email));
    const name = u.display_name || (u.email ? u.email.split("@")[0] : "Athlete");
    const avatar = u.profile_image
      ? `<img src="${escapeHtml(u.profile_image)}" alt="" style="width:32px;height:32px;border-radius:50%;object-fit:cover;">`
      : `<div style="width:32px;height:32px;border-radius:50%;background:linear-gradient(135deg,#3b82f6,#8b5cf6);display:flex;align-items:center;justify-content:center;color:#fff;font-weight:700;font-size:13px;">${escapeHtml((name.charAt(0) || "?").toUpperCase())}</div>`;
    const viewAttr = u._local ? "" : `data-view-user-id="${escapeHtml(u.id || "")}" data-view-user-name="${escapeHtml(name)}" data-view-user-email="${escapeHtml(u.email || "")}" data-view-user-avatar="${escapeHtml(u.profile_image || "")}" role="button" tabindex="0" style="cursor:pointer;"`;
    return `<div class="account-search-item"><div class="account-search-row" ${viewAttr} style="display:flex;gap:10px;align-items:center;${u._local ? "" : "cursor:pointer;"}">${avatar}<div style="flex:1;min-width:0;"><strong>${escapeHtml(name)}</strong>${u._local ? `<small style="display:block;color:#94a3b8;">lokal</small>` : `<small style="display:block;color:#94a3b8;">Profil ansehen →</small>`}</div><div class="account-search-actions"><button type="button" class="ghost" data-home-connect-email="${escapeHtml(u.email)}" data-home-connect-id="${escapeHtml(u.id || "")}" ${isConnected ? "disabled" : ""}>${isConnected ? "Verbunden" : "Verbinden"}</button></div></div></div>`;
  }).join("");

  // Wire "view profile" click on rows (ignore button clicks)
  resultsEl.querySelectorAll("[data-view-user-id]").forEach((row) => {
    row.addEventListener("click", (e) => {
      if (e.target.closest("button")) return; // let Connect button handle itself
      const uid = row.getAttribute("data-view-user-id");
      if (!uid) return;
      viewUserPublicProfile({
        id: uid,
        display_name: row.getAttribute("data-view-user-name"),
        email: row.getAttribute("data-view-user-email"),
        profile_image: row.getAttribute("data-view-user-avatar") || null,
      });
    });
    row.addEventListener("keydown", (e) => {
      if (e.key === "Enter" || e.key === " ") { e.preventDefault(); row.click(); }
    });
  });

  resultsEl.querySelectorAll("[data-home-connect-email]").forEach((btn) => {
    btn.addEventListener("click", async (e) => {
      e.stopPropagation();
      const email = btn.getAttribute("data-home-connect-email");
      const friendId = btn.getAttribute("data-home-connect-id");
      // Try remote friend request first
      if (friendId && !friendId.includes("@") && typeof sendConnectRequest === "function") {
        try { await sendConnectRequest(friendId); } catch (_) {}
      }
      const result = addFriendByEmail(account, email);
      if (result.ok) persistStore();
      btn.disabled = true; btn.textContent = "Angefragt";
      renderAccountUi();
    });
  });
}

document.getElementById("home-athlete-search-form")?.addEventListener("submit", (event) => {
  event.preventDefault();
  const query = String(new FormData(event.target).get("query") || "").trim();
  runHomeAthleteSearch(query);
});

// Live debounced search on home-athlete input too
let _homeLiveTimer = 0;
document.addEventListener("input", (event) => {
  const el = event.target;
  if (!el || el.closest?.("#home-athlete-search-form") == null) return;
  if (el.name !== "query") return;
  clearTimeout(_homeLiveTimer);
  const val = el.value;
  _homeLiveTimer = setTimeout(() => runHomeAthleteSearch(val), 300);
});

// ============================================================
// Athleten Drawer (header icon → slide-in panel)
// ============================================================
let _athletesSearchSeq = 0;
let _athletesLiveTimer = 0;

function openAthletesDrawer() {
  const backdrop = document.getElementById("athletes-drawer-backdrop");
  if (!backdrop) return;
  backdrop.hidden = false;
  document.body.classList.add("athletes-drawer-open");
  renderAthletesDrawer(getCurrentAccount());
  setTimeout(() => document.getElementById("athletes-search-input")?.focus(), 50);
}

function closeAthletesDrawer() {
  const backdrop = document.getElementById("athletes-drawer-backdrop");
  if (!backdrop) return;
  backdrop.hidden = true;
  document.body.classList.remove("athletes-drawer-open");
  // Reset search UI
  const resultsWrap = document.getElementById("athletes-drawer-results-wrap");
  const results = document.getElementById("athletes-drawer-results");
  const input = document.getElementById("athletes-search-input");
  if (resultsWrap) resultsWrap.hidden = true;
  if (results) results.innerHTML = "";
  if (input) input.value = "";
}

function renderAthletesDrawer(account) {
  const connectedList = document.getElementById("athletes-drawer-connected");
  const connectedCount = document.getElementById("athletes-drawer-connected-count");
  const headerCount = document.getElementById("athletes-header-count");
  if (!connectedList) return;

  const friendEmails = account?.friends || [];
  if (connectedCount) connectedCount.textContent = String(friendEmails.length);
  if (headerCount) {
    if (friendEmails.length > 0) {
      headerCount.hidden = false;
      headerCount.textContent = friendEmails.length > 99 ? "99+" : String(friendEmails.length);
    } else {
      headerCount.hidden = true;
    }
  }

  if (!account || !friendEmails.length) {
    connectedList.innerHTML = `<div class="athletes-drawer-empty">Noch keine Verbindungen.</div>`;
    return;
  }

  connectedList.innerHTML = friendEmails.map((email) => {
    const friend = (appStore?.accounts || []).find((a) => a.email === email);
    const name = friend ? resolveDisplayName(friend) : email.split("@")[0];
    const avatar = friend?.profileImage
      ? `<img class="athletes-drawer-avatar" src="${escapeHtml(friend.profileImage)}" alt="">`
      : `<div class="athletes-drawer-avatar is-fallback">${escapeHtml((name.charAt(0) || "?").toUpperCase())}</div>`;
    return `<div class="athletes-drawer-item">${avatar}<div class="athletes-drawer-meta"><div class="athletes-drawer-name">${escapeHtml(name)}</div><div class="athletes-drawer-sub">${escapeHtml(email)}</div></div></div>`;
  }).join("");
}

async function runAthletesDrawerSearch(query) {
  const resultsWrap = document.getElementById("athletes-drawer-results-wrap");
  const resultsEl = document.getElementById("athletes-drawer-results");
  if (!resultsEl || !resultsWrap) return;
  const account = getCurrentAccount();
  if (!account) return;
  const q = String(query || "").trim();
  if (!q) {
    resultsWrap.hidden = true;
    resultsEl.innerHTML = "";
    return;
  }
  resultsWrap.hidden = false;
  resultsEl.innerHTML = `<div class="athletes-drawer-empty">Suche …</div>`;
  const seq = ++_athletesSearchSeq;

  const remote = window.sbDb?.searchUsers
    ? await window.sbDb.searchUsers(q, 12).catch(() => [])
    : [];
  if (seq !== _athletesSearchSeq) return;

  const lo = q.toLowerCase();
  const local = (appStore?.accounts || [])
    .filter((a) => a.email !== account.email)
    .filter((a) => {
      const name = (a.email ? a.email.split("@")[0] : a.displayName || "Athlete").toLowerCase();
      const displayName = (a.displayName || "").toLowerCase();
      return name.includes(lo) || displayName.includes(lo) || a.email.toLowerCase().includes(lo);
    })
    .map((a) => ({ id: a.email, email: a.email, display_name: a.displayName || a.email.split("@")[0], profile_image: a.profileImage || null, _local: true }));

  const seen = new Set();
  const merged = [];
  remote.filter((r) => r.email && r.email !== account.email).forEach((r) => {
    if (seen.has(r.email)) return;
    seen.add(r.email); merged.push(r);
  });
  local.forEach((l) => { if (!seen.has(l.email)) { seen.add(l.email); merged.push(l); } });

  if (!merged.length) {
    resultsEl.innerHTML = `<div class="athletes-drawer-empty">Keine Athleten gefunden.</div>`;
    return;
  }

  resultsEl.innerHTML = merged.slice(0, 12).map((u) => {
    const isConnected = Boolean(account.friends?.includes(u.email));
    const name = u.display_name || (u.email ? u.email.split("@")[0] : "Athlete");
    const avatar = u.profile_image
      ? `<img class="athletes-drawer-avatar" src="${escapeHtml(u.profile_image)}" alt="">`
      : `<div class="athletes-drawer-avatar is-fallback">${escapeHtml((name.charAt(0) || "?").toUpperCase())}</div>`;
    const viewAttr = u._local ? "" : `data-view-user-id="${escapeHtml(u.id || "")}" data-view-user-name="${escapeHtml(name)}" data-view-user-email="${escapeHtml(u.email || "")}" data-view-user-avatar="${escapeHtml(u.profile_image || "")}" role="button" tabindex="0"`;
    return `<div class="athletes-drawer-item" ${viewAttr} style="${u._local ? "" : "cursor:pointer;"}">${avatar}<div class="athletes-drawer-meta"><div class="athletes-drawer-name">${escapeHtml(name)}</div><div class="athletes-drawer-sub">${escapeHtml(u.email)}${u._local ? " • lokal" : ""}</div></div><button type="button" class="athletes-drawer-action${isConnected ? " is-connected" : ""}" data-athletes-connect-email="${escapeHtml(u.email)}" data-athletes-connect-id="${escapeHtml(u.id || "")}" ${isConnected ? "disabled" : ""}>${isConnected ? "Verbunden" : "Verbinden"}</button></div>`;
  }).join("");

  // Wire click-to-view-profile on drawer rows (ignore button clicks)
  resultsEl.querySelectorAll("[data-view-user-id]").forEach((row) => {
    row.addEventListener("click", (e) => {
      if (e.target.closest("button")) return;
      const uid = row.getAttribute("data-view-user-id");
      if (!uid) return;
      viewUserPublicProfile({
        id: uid,
        display_name: row.getAttribute("data-view-user-name"),
        email: row.getAttribute("data-view-user-email"),
        profile_image: row.getAttribute("data-view-user-avatar") || null,
      });
    });
    row.addEventListener("keydown", (e) => {
      if (e.key === "Enter" || e.key === " ") { e.preventDefault(); row.click(); }
    });
  });

  resultsEl.querySelectorAll("[data-athletes-connect-email]").forEach((btn) => {
    btn.addEventListener("click", async (e) => {
      e.stopPropagation();
      const email = btn.getAttribute("data-athletes-connect-email");
      const friendId = btn.getAttribute("data-athletes-connect-id");
      if (friendId && !friendId.includes("@") && typeof sendConnectRequest === "function") {
        try { await sendConnectRequest(friendId); } catch (_) {}
      }
      const result = addFriendByEmail(account, email);
      if (result.ok) persistStore();
      btn.disabled = true; btn.textContent = "Angefragt";
      renderAccountUi();
    });
  });
}

