function drawStickFrame(frame) {
  const { x, y } = frame;
  const head = `<circle cx="${x}" cy="${y - 12}" r="2.8" fill="rgba(255,255,255,0.82)"/>`;
  const torsoY2 = y + (frame.bend || 0) * 0.6;
  const torso = `<line x1="${x}" y1="${y - 9}" x2="${x}" y2="${torsoY2}" stroke="rgba(255,255,255,0.82)" stroke-width="1.4" stroke-linecap="round"/>`;
  const arms = {
    down: [[x, y - 6, x - 5, y + 2], [x, y - 6, x + 5, y + 2]],
    up: [[x, y - 7, x - 6, y - 13], [x, y - 7, x + 6, y - 13]],
    floor: [[x, y - 5, x - 7, y + 8], [x, y - 5, x + 7, y + 8]],
    push: [[x, y - 6, x - 8, y + 4], [x, y - 6, x + 8, y + 4]],
    front: [[x, y - 6, x - 5, y - 1], [x, y - 6, x + 5, y - 1]],
    carry: [[x, y - 6, x - 4, y + 4], [x, y - 6, x + 4, y + 4]],
    run1: [[x, y - 6, x - 6, y - 2], [x, y - 6, x + 5, y + 1]],
    run2: [[x, y - 6, x - 4, y + 1], [x, y - 6, x + 6, y - 2]],
    bar: [[x, y - 7, x - 6, y - 4], [x, y - 7, x + 6, y - 4]],
    swim1: [[x, y - 7, x - 6, y - 10], [x, y - 7, x + 7, y - 6]],
    swim2: [[x, y - 7, x - 2, y - 12], [x, y - 7, x + 8, y - 2]],
    swim3: [[x, y - 7, x - 8, y - 3], [x, y - 7, x + 4, y - 11]],
    deadbug1: [[x, y - 6, x - 7, y - 9], [x, y - 6, x + 5, y - 2]],
    deadbug2: [[x, y - 6, x - 5, y - 2], [x, y - 6, x + 7, y - 9]],
    reach: [[x, y - 6, x - 7, y - 12], [x, y - 6, x + 4, y - 1]],
    reach2: [[x, y - 6, x + 7, y - 12], [x, y - 6, x - 4, y - 1]],
    rotate: [[x, y - 6, x - 6, y - 4], [x, y - 6, x + 6, y - 8]],
  }[frame.arms || "down"];
  const legs = {
    narrow: [[x, torsoY2, x - 4, y + 11], [x, torsoY2, x + 4, y + 11]],
    wide: [[x, torsoY2, x - 7, y + 10], [x, torsoY2, x + 7, y + 10]],
    split: [[x, torsoY2, x - 7, y + 11], [x, torsoY2, x + 4, y + 8]],
    split2: [[x, torsoY2, x - 4, y + 8], [x, torsoY2, x + 7, y + 11]],
    back: [[x, torsoY2, x - 8, y + 8], [x, torsoY2, x + 8, y + 8]],
    run1: [[x, torsoY2, x - 6, y + 10], [x, torsoY2, x + 7, y + 6]],
    run2: [[x, torsoY2, x - 4, y + 6], [x, torsoY2, x + 8, y + 10]],
    run3: [[x, torsoY2, x - 8, y + 8], [x, torsoY2, x + 5, y + 7]],
    walk1: [[x, torsoY2, x - 5, y + 10], [x, torsoY2, x + 6, y + 8]],
    walk2: [[x, torsoY2, x - 6, y + 8], [x, torsoY2, x + 5, y + 10]],
    bike1: [[x, torsoY2, x - 6, y + 7], [x, torsoY2, x + 5, y + 10]],
    bike2: [[x, torsoY2, x - 4, y + 10], [x, torsoY2, x + 7, y + 7]],
    stream: [[x, torsoY2, x - 7, y + 2], [x, torsoY2, x + 7, y + 2]],
    deadbug1: [[x, torsoY2, x - 6, y + 10], [x, torsoY2, x + 6, y + 4]],
    deadbug2: [[x, torsoY2, x - 6, y + 4], [x, torsoY2, x + 6, y + 10]],
  }[frame.legs || "narrow"];

  const lines = [...arms, ...legs]
    .map(([x1, y1, x2, y2]) => `<line x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}" stroke="rgba(255,255,255,0.82)" stroke-width="1.2" stroke-linecap="round"/>`)
    .join("");
  const extraCarry = frame.arms === "carry"
    ? `<rect x="${x - 7.8}" y="${y + 3.4}" width="2.8" height="2.8" rx="0.7" fill="rgba(255,255,255,0.55)"/><rect x="${x + 5}" y="${y + 3.4}" width="2.8" height="2.8" rx="0.7" fill="rgba(255,255,255,0.55)"/>`
    : "";
  const extraBike = frame.arms === "bar"
    ? `<circle cx="${x - 8}" cy="${y + 10}" r="3.8" fill="none" stroke="rgba(255,255,255,0.35)" stroke-width="1"/><circle cx="${x + 9}" cy="${y + 10}" r="3.8" fill="none" stroke="rgba(255,255,255,0.35)" stroke-width="1"/>`
    : "";
  const ground = `<line x1="${x - 11}" y1="${y + 12.5}" x2="${x + 11}" y2="${y + 12.5}" stroke="rgba(255,255,255,0.12)" stroke-width="0.8"/>`;
  return `<g>${ground}${head}${torso}${lines}${extraCarry}${extraBike}</g>`;
}

function renderGlossary() {
  if (!glossaryListEl) return;
  const q = String(glossarySearchEl?.value || "").trim().toLowerCase();
  const cat = String(glossaryCategoryEl?.value || "all");
  const rows = TRAINING_GLOSSARY
    .filter((item) => cat === "all" || item.category === cat)
    .filter((item) => !q || [item.term, item.text, item.detail, ...(item.cues || []), ...(item.steps || [])].join(" ").toLowerCase().includes(q))
    .sort((a, b) => a.term.localeCompare(b.term));

  if (!rows.length) {
    glossaryListEl.innerHTML = `<div class="empty-copy">Keine Treffer in der Trainingsbibliothek.</div>`;
    return;
  }

  const grouped = rows.reduce((acc, item) => {
    if (!acc[item.category]) acc[item.category] = [];
    acc[item.category].push(item);
    return acc;
  }, {});
  const categories = Object.keys(grouped).sort((a, b) => glossaryCategoryLabel(a).localeCompare(glossaryCategoryLabel(b)));
  if (q) categories.forEach((category) => glossaryOpenCategories.add(category));

  glossaryListEl.innerHTML = categories.map((category) => {
    const categoryId = `cat_${category}`;
    const categoryOpen = glossaryOpenCategories.has(category);
    const itemsHtml = grouped[category].map((item) => {
      const itemKey = `${category}::${item.term}`;
      const itemOpen = glossaryOpenTerms.has(itemKey);
      const cues = (item.cues || []).map((cue) => `<li>${escapeHtml(cue)}</li>`).join("");
      const steps = (item.steps || []).map((step) => `<li>${escapeHtml(step)}</li>`).join("");
      return `
        <article class="glossary-item ${itemOpen ? "is-open" : ""}">
          <button type="button" class="glossary-item-toggle" data-glossary-item="${escapeHtml(itemKey)}" aria-expanded="${itemOpen}">
            <div class="glossary-item-head">
              <strong>${escapeHtml(item.term)}</strong>
              <span class="glossary-chevron">${itemOpen ? "−" : "+"}</span>
            </div>
            <p>${escapeHtml(item.text)}</p>
          </button>
          <div class="glossary-item-detail" ${itemOpen ? "" : "hidden"}>
            ${renderExerciseVisual(item)}
            <div class="glossary-item-detail-grid">
              <div class="glossary-detail-block">
                <span>${currentLang === "de" ? "So setzt du es ein" : currentLang === "ja" ? "使い方" : "How to use it"}</span>
                <strong>${escapeHtml(item.detail || item.text)}</strong>
              </div>
              ${steps ? `<div class="glossary-detail-block"><span>${currentLang === "de" ? "Ablauf" : currentLang === "ja" ? "流れ" : "Flow"}</span><ul>${steps}</ul></div>` : ""}
              ${cues ? `<div class="glossary-detail-block"><span>${currentLang === "de" ? "Wichtige Cues" : currentLang === "ja" ? "キュー" : "Key cues"}</span><ul>${cues}</ul></div>` : ""}
            </div>
          </div>
        </article>`;
    }).join("");

    return `
      <section class="glossary-category ${categoryOpen ? "is-open" : ""}">
        <button type="button" class="glossary-category-toggle" data-glossary-category="${escapeHtml(category)}" aria-expanded="${categoryOpen}">
          <strong>${escapeHtml(glossaryCategoryLabel(category))}</strong>
          <span>${grouped[category].length}</span>
        </button>
        <div class="glossary-category-body" ${categoryOpen ? "" : "hidden"}>
          ${itemsHtml}
        </div>
      </section>`;
  }).join("");
}

function loadStore() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return { accounts: [], currentAccountId: null };
    const parsed = JSON.parse(raw);
    return {
      accounts: Array.isArray(parsed.accounts) ? parsed.accounts : [],
      currentAccountId: parsed.currentAccountId || null,
    };
  } catch {
    return { accounts: [], currentAccountId: null };
  }
}

// ── Debounced persist: localStorage write batched to max 1× per 2s ──
// Keys to strip from localStorage entirely — activities live in Supabase,
// no reason to duplicate them in the browser's 5 MB quota.
const _PERSIST_SKIP_KEYS = new Set([
  "polyline", "metrics", "imageDataUrl",  // heavy fields
  "activities",                            // 0 activities in localStorage
]);

function _flushPersistStore() {
  if (!appStore) return;
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(appStore, function (key, value) {
      if (_PERSIST_SKIP_KEYS.has(key)) return undefined;
      return value;
    }));
  } catch (e) {
    console.warn("persistStore failed:", e);
  }
}

function persistStore() {
  if (!appStore) return;
  appStore.currentAccountId = currentAccountId;
  const acc = appStore.accounts.find((a) => a.id === currentAccountId);
  if (acc && acc.settings) {
    acc.settings._updatedAt = Date.now();
  }
  // Debounce localStorage write — max 1× per 2 seconds
  clearTimeout(persistStore._lsTimer);
  persistStore._lsTimer = setTimeout(_flushPersistStore, 2000);
  // Debounced cloud sync
  if (acc && typeof sbDb !== "undefined" && sbDb?.updateProfile) {
    clearTimeout(persistStore._cloudTimer);
    persistStore._cloudTimer = setTimeout(() => {
      sbDb.updateProfile(acc.id, { settings: acc.settings }).catch(() => {});
    }, 800);
  }
}
// Flush on page unload so nothing is lost
window.addEventListener("beforeunload", _flushPersistStore);

function getCurrentAccount() {
  if (!appStore || !currentAccountId) return null;
  const account = appStore.accounts.find((a) => a.id === currentAccountId) || null;
  if (account) {
    ensureAccountSettingsShape(account);
    ensureAccountIntegrationsShape(account);
  }
  return account;
}

function ensureAccountSettingsShape(account) {
  if (!account) return;
  const defaults = defaultAccountSettings();
  account.settings = account.settings || {};
  account.settings.account = { ...defaults.account, ...(account.settings.account || {}) };
  account.settings.privacy = { ...defaults.privacy, ...(account.settings.privacy || {}) };
  account.settings.safety = { ...defaults.safety, ...(account.settings.safety || {}) };
}

function ensureAccountIntegrationsShape(account) {
  if (!account) return;
  account.integrations = account.integrations || {};
  account.integrations.strava = {
    connected: false,
    lastStatusAt: null,
    lastImportAt: null,
    userId: null,
    athlete: null,
    expires_at: null,
    scope: null,
    error: null,
    importSummary: null,
    ...(account.integrations.strava || {}),
  };
}

function setAuthMode(mode) {
  authMode = mode === "register" ? "register" : "login";
  accountTabButtons.forEach((btn) => btn.classList.toggle("is-active", btn.dataset.authMode === authMode));
  if (accountSubmitBtn) accountSubmitBtn.textContent = authMode === "register" ? "create." : "login.";
  if (accountFormStatusEl) accountFormStatusEl.textContent = "";
  // Only require terms acceptance on registration
  const termsField = document.getElementById("auth-terms-field");
  if (termsField) termsField.hidden = authMode !== "register";
}

function openAccountModal(mode = authMode) {
  if (!accountModalEl) return;
  setAuthMode(mode);
  accountModalEl.hidden = false;
}

function closeAccountModal() {
  if (!accountModalEl) return;
  accountModalEl.hidden = true;
}

async function registerAccount(email, password) {
  if (!email || !email.includes("@")) return { ok: false, message: "Bitte gültige E-Mail eingeben." };
  if (!password || password.length < 6) return { ok: false, message: "Passwort muss mindestens 6 Zeichen haben." };

  try {
    const data = await sbAuth.signUp(email, password);
    if (data.user) {
      await handleSupabaseAuth(data.session);
      return { ok: true, message: "Account erstellt." };
    }
    return { ok: true, message: "Bestätigungs-E-Mail gesendet. Bitte Postfach prüfen." };
  } catch (err) {
    const msg = err.message?.includes("already registered") ? "E-Mail existiert bereits." : err.message || "Fehler bei der Registrierung.";
    return { ok: false, message: msg };
  }
}

async function loginAccount(email, password) {
  try {
    const data = await sbAuth.signIn(email, password);
    await handleSupabaseAuth(data.session);
    return { ok: true, message: "Eingeloggt." };
  } catch (err) {
    const msg = err.message?.includes("Invalid login") ? "E-Mail oder Passwort falsch." : err.message || "Login fehlgeschlagen.";
    return { ok: false, message: msg };
  }
}

async function handleSupabaseAuth(session) {
  if (!session?.user) return;
  const user = session.user;
  // Create local account representation backed by Supabase
  let account = appStore.accounts.find((a) => a.id === user.id);
  if (!account) {
    account = {
      id: user.id,
      email: user.email,
      createdAt: user.created_at || new Date().toISOString(),
      plans: [],
      friends: [],
      connectedSources: [],
      settings: defaultAccountSettings(),
    };
    appStore.accounts.push(account);
  }
  // Sync profile from Supabase
  try {
    const profile = await sbDb.getProfile(user.id);
    if (profile) {
      account.email = profile.email || account.email;
      account.displayName = profile.display_name;
      account.profileImage = profile.profile_image;
      if (profile.settings) {
        // Merge remote + local settings. If local has a newer _updatedAt timestamp,
        // local wins — otherwise remote wins. This prevents reloads from wiping
        // settings that were changed locally but hadn't synced yet.
        const remote = profile.settings;
        const local = account.settings || {};
        const localNewer = (local._updatedAt || 0) > (remote._updatedAt || 0);
        account.settings = localNewer
          ? { ...defaultAccountSettings(), ...remote, ...local }
          : { ...defaultAccountSettings(), ...local, ...remote };
      }
      if (profile.connected_sources) account.connectedSources = profile.connected_sources;
    }
    // Load plans from Supabase — merge with local by ID (local-only plans survive)
    const remotePlans = await sbDb.getPlans(user.id);
    if (remotePlans.length) {
      const remoteMapped = remotePlans.map((p) => ({
        id: p.id,
        createdAt: p.created_at,
        title: p.title,
        summary: p.summary,
        profile: p.profile,
        plan: p.plan_data,
      }));
      const byId = new Map();
      (account.plans || []).forEach((p) => byId.set(p.id, p));
      remoteMapped.forEach((p) => byId.set(p.id, p)); // remote wins on conflict
      account.plans = Array.from(byId.values()).sort(
        (a, b) => new Date(b.createdAt || 0) - new Date(a.createdAt || 0)
      );
    }
    // Load recent activities for feed only (stats come from server-side views)
    const activities = await sbDb.getActivities(user.id, 200);
    if (activities.length) {
      account.activities = activities.map((a) => {
        const m = a.metrics || {};
        return {
          id: a.id,
          source: a.source,
          sourceExternalId: a.source_external_id,
          createdAt: a.created_at,
          title: a.title,
          note: a.note,
          kind: a.kind,
          sportType: a.sport_type,
          distanceKm: +a.distance_km || 0,
          movingTimeSec: a.moving_time_sec,
          elevationGainM: a.elevation_gain_m,
          imageDataUrl: a.image_url,
          polyline: a.polyline || null,
          // Translate snake_case metrics back to camelCase the UI expects
          avgHeartrate: m.avg_heartrate || null,
          maxHeartrate: m.max_heartrate || null,
          avgWatts: m.avg_watts || null,
          maxWatts: m.max_watts || null,
          weightedAvgWatts: m.weighted_avg_watts || null,
          sufferScore: m.suffer_score || null,
          avgCadence: m.avg_cadence || null,
          propsBy: [],
          metrics: m, // keep original for detail modal
        };
      });
    }
  } catch (e) {
    console.warn("Supabase sync error (non-blocking):", e);
  }
  currentAccountId = user.id;
  persistStore();
  hydrateConnectedSourcesFromAccount();
  document.body.classList.add("is-authenticated");

  // Load notifications for this user
  if (typeof _loadNotifications === "function") _loadNotifications();

  // Auto-sync new Strava activities in background (non-blocking)
  autoSyncStravaOnLogin(account);
}

/**
 * Silently fetch the latest Strava activities since last import and upsert
 * them to Supabase + local feed. Runs once per login, non-blocking.
 */
async function autoSyncStravaOnLogin(account) {
  try {
    if (!account?.integrations?.strava?.connected) return;
    const userId = getStravaLocalUserId(account);
    if (!userId) return;
    const lastImport = account.integrations.strava.lastImportAt;
    // Fetch only the last 1-2 pages (most recent activities since last import)
    const afterEpoch = lastImport ? Math.floor(new Date(lastImport).getTime() / 1000) - 3600 : 0;
    const url = afterEpoch
      ? `${STRAVA_OAUTH_DEV_BASE}/api/oauth/strava/activities?user_id=${encodeURIComponent(userId)}&page=1&per_page=200&after=${afterEpoch}`
      : `${STRAVA_OAUTH_DEV_BASE}/api/oauth/strava/activities?user_id=${encodeURIComponent(userId)}&page=1&per_page=50`;
    const res = await fetch(url, { method: "GET", headers: { Accept: "application/json" }, cache: "no-store" });
    const json = await res.json().catch(() => ({}));
    if (!res.ok || !Array.isArray(json?.activities) || !json.activities.length) return;
    const acts = json.activities;
    console.log(`[Strava auto-sync] ${acts.length} new activities since ${lastImport || "beginning"}`);
    // Upsert to Supabase
    if (window.sbDb && account.id) {
      try { await sbDb.upsertStravaActivities(account.id, acts); } catch (_) {}
    }
    // Merge into local feed
    mergeStravaActivitiesIntoLocalAccount(account, acts);
    account.integrations.strava.lastImportAt = new Date().toISOString();
    persistStore();
    // Refresh server-side stats
    if (window.sbStats && _isUuid(account.id)) { sbStats.invalidateCache(account.id); sbStats.refreshStats().catch(() => {}); }
    // Notify user about new activities
    if (acts.length && typeof addNotification === "function") {
      const latest = acts[0];
      const title = acts.length === 1 ? (latest.name || "Neue Aktivität") : `${acts.length} neue Aktivitäten`;
      addNotification("activity_new", title, acts.length === 1 ? `${(latest.distance / 1000).toFixed(1)} km` : "Automatisch synchronisiert");
    }
    renderAccountUi();
    try { if (window.MedalBoard?.scanActivitiesQuiet) window.MedalBoard.scanActivitiesQuiet(); } catch (_) {}
  } catch (e) {
    console.warn("[Strava auto-sync] failed (non-blocking):", e?.message || e);
  }
}

async function requestPasswordReset(email) {
  const normalized = String(email || "").trim().toLowerCase();
  if (!normalized || !normalized.includes("@")) {
    return { ok: false, message: "Bitte zuerst eine gültige E-Mail eingeben." };
  }
  try {
    await sb.auth.resetPasswordForEmail(normalized, {
      redirectTo: window.location.origin + window.location.pathname,
    });
    return { ok: true, message: "Reset-Link gesendet. Bitte Postfach prüfen." };
  } catch (err) {
    return { ok: false, message: err.message || "Fehler beim Senden." };
  }
}

async function changeCurrentAccountPassword(currentPassword, newPassword) {
  const account = getCurrentAccount();
  if (!account) return { ok: false, message: "Bitte zuerst einloggen." };
  if (!newPassword || newPassword.length < 6) return { ok: false, message: "Neues Passwort muss mindestens 6 Zeichen haben." };
  try {
    const { error } = await sb.auth.updateUser({ password: newPassword });
    if (error) throw error;
    return { ok: true, message: "Passwort aktualisiert." };
  } catch (err) {
    return { ok: false, message: err.message || "Fehler beim Ändern." };
  }
}

function exportCurrentAccountData() {
  const account = getCurrentAccount();
  if (!account) return { ok: false, message: "Bitte zuerst einloggen." };
  const safeAccount = JSON.parse(JSON.stringify(account));
  delete safeAccount.password;
  downloadTextFile({
    content: JSON.stringify(
      {
        exportedAt: new Date().toISOString(),
        schema: "aimathlete-local-mvp-account-export-v1",
        account: safeAccount,
      },
      null,
      2
    ),
    filename: `aimathlete-account-export-${slugify((account.email ? account.email.split("@")[0] : account.displayName || "user") || "user")}.json`,
    mimeType: "application/json;charset=utf-8",
  });
  return { ok: true, message: "Export erstellt." };
}

function deleteCurrentAccountLocalMvp() {
  const account = getCurrentAccount();
  if (!account) return { ok: false, message: "Bitte zuerst einloggen." };
  const confirmed = window.confirm(`Account ${account.email} lokal löschen? Diese Aktion betrifft nur diesen Browser (MVP).`);
  if (!confirmed) return { ok: false, message: "Abgebrochen." };
  appStore.accounts = (appStore.accounts || []).filter((a) => a.id !== account.id);
  currentAccountId = null;
  connectedSources.clear();
  persistStore();
  syncConnectorButtons();
  renderAccountUi();
  return { ok: true, message: "Account lokal gelöscht." };
}

async function logoutCurrentAccount() {
  try { await sbAuth.signOut(); } catch (e) { /* ignore */ }
  currentAccountId = null;
  connectedSources.clear();
  connectorButtons.forEach((b) => b.classList.remove("active"));
  latestProfile = null;
  latestPlan = null;
  generatedSessions = [];
  persistStore();
  document.body.classList.remove("is-authenticated");
  stravaStatusFetchedForUserId = null;
  setText(connectionState, t("no_sources"));

  // Clear fitness age hero
  const faHero = document.getElementById("fitness-age-hero-value");
  if (faHero) faHero.textContent = "--";
  const faDelta = document.getElementById("fitness-age-hero-delta");
  if (faDelta) faDelta.textContent = "";

  // Clear factor bars
  document.querySelectorAll(".factor-fill").forEach(f => f.style.width = "0%");

  // Clear activity feed
  const activityFeedContainer = document.getElementById("activity-feed-container");
  if (activityFeedContainer) activityFeedContainer.innerHTML = "";

  // Reset to home view, then re-render everything
  setAppView("home");
  renderAccountUi();
}

function hydrateConnectedSourcesFromAccount() {
  connectedSources.clear();
  const account = getCurrentAccount();
  (account?.connectedSources || []).forEach((src) => connectedSources.add(src));
}

function persistConnectedSourcesForCurrentUser() {
  const account = getCurrentAccount();
  if (!account) return;
  account.connectedSources = [...connectedSources];
  persistStore();
}

function syncConnectorButtons() {
  connectorButtons.forEach((button) => {
    const source = button.dataset.source;
    button.classList.toggle("active", connectedSources.has(source));
  });
}

function savePlanToLibrary(account, profile, plan) {
  account.plans = Array.isArray(account.plans) ? account.plans : [];
  const title = `${disciplineLabel(profile.discipline)} • ${labelDistance(profile.goalDistance)} • ${profile.goalTime}`;
  const summary = `${plan.weeks.length} Wochen • ${Math.round(plan.meta.weeklyKmBase)} Base`;
  const serializedProfile = serializeProfile(profile);
  const serializedPlan = serializePlan(plan);
  const item = {
    id: `plan_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
    createdAt: new Date().toISOString(),
    title,
    summary,
    profile: serializedProfile,
    plan: serializedPlan,
  };
  account.plans.unshift(item);
  account.plans = account.plans.slice(0, 20);

  // Sync to Supabase in background
  if (typeof sbDb !== "undefined" && account.id && !account.id.startsWith("acc_")) {
    sbDb.savePlan(account.id, { title, summary, profile: serializedProfile, plan_data: serializedPlan })
      .then((saved) => {
        if (saved?.id) {
          item.id = saved.id;
          // Sync A+B race events → user_target_races (Main Events on profile)
          const raceEvents = Array.isArray(profile?.raceEvents) ? profile.raceEvents : [];
          if (raceEvents.length && window.MainEvents?.syncFromPlan) {
            window.MainEvents.syncFromPlan(account.id, saved.id, raceEvents);
          }
        }
      })
      .catch((e) => console.warn("Plan sync error:", e));
  }
}

function serializeProfile(profile) {
  return {
    ...profile,
    raceDate: profile?.raceDate instanceof Date ? profile.raceDate.toISOString() : profile?.raceDate,
  };
}

function serializePlan(plan) {
  return {
    ...plan,
    weeks: (plan.weeks || []).map((week) => ({
      ...week,
      weekStart: week.weekStart instanceof Date ? week.weekStart.toISOString() : week.weekStart,
      days: (week.days || []).map((day) => ({
        ...day,
        date: day.date instanceof Date ? day.date.toISOString() : day.date,
      })),
    })),
    sessions: (plan.sessions || []).map((session) => ({
      ...session,
      date: session.date instanceof Date ? session.date.toISOString() : session.date,
    })),
  };
}

function hydrateStoredProfile(profile) {
  return {
    ...profile,
    raceDate: profile?.raceDate ? new Date(profile.raceDate) : null,
    raceEvents: parseRaceEventsJson(JSON.stringify(Array.isArray(profile?.raceEvents) ? profile.raceEvents : [])),
  };
}

function hydrateStoredPlan(plan) {
  return {
    ...plan,
    weeks: (plan.weeks || []).map((week) => ({
      ...week,
      weekStart: week.weekStart ? new Date(week.weekStart) : null,
      days: (week.days || []).map((day) => ({
        ...day,
        date: day.date ? new Date(day.date) : null,
      })),
    })),
    sessions: (plan.sessions || []).map((session, index) => ({
      ...session,
      _id: session._id || `session-${index}`,
      date: session.date ? new Date(session.date) : null,
    })),
  };
}

function loadSavedPlanById(planId) {
  const account = getCurrentAccount();
  if (!account) return;
  const item = (account.plans || []).find((p) => p.id === planId);
  if (!item) return;
  latestProfile = hydrateStoredProfile(item.profile);
  latestPlan = hydrateStoredPlan(item.plan);
  generatedSessions = latestPlan.sessions || [];
  // Adapt plan to current reality before rendering
  maybeAdaptPlan();
  renderAnalysis(latestProfile, latestPlan);
  renderPlan(latestPlan);
  renderPerformanceInsights(latestProfile, latestPlan);
  renderProfilePredictions(latestProfile, latestPlan);
  exportIcalBtn.disabled = generatedSessions.length === 0;
  document.body.classList.add("has-output");
  syncUiState();
}

function addFriendByEmail(account, email) {
  if (!email || !email.includes("@")) return { ok: false, message: t("invalid_email") };
  if (email === account.email) return { ok: false, message: t("own_email_not_allowed") };
  const exists = appStore.accounts.find((a) => a.email === email);
  if (!exists) return { ok: false, message: t("account_not_found_local") };
  account.friends = Array.isArray(account.friends) ? account.friends : [];
  if (!account.friends.includes(email)) account.friends.push(email);
  persistStore();
  return { ok: true, message: t("connected") };
}

// ── Safe render wrapper: isolates each render call so one crash doesn't kill the rest ──
function _safeRender(name, fn) {
  try { fn(); } catch (e) { console.warn(`[Render] ${name} failed:`, e); }
}

// Debounce renderAccountUi: coalesce multiple calls into one rAF
let _renderAccountUiScheduled = false;
function renderAccountUi() {
  if (_renderAccountUiScheduled) return;
  _renderAccountUiScheduled = true;
  requestAnimationFrame(() => {
    _renderAccountUiScheduled = false;
    _renderAccountUiImpl();
  });
}
function _renderAccountUiImpl() {
  const account = getCurrentAccount();
  const isAuth = Boolean(account);
  if (!isAuth) {
    // Clear dashboard data for logged-out state
    const ringsContainer = document.getElementById("dashboard-rings-container");
    if (ringsContainer) ringsContainer.querySelectorAll(".ring-value").forEach(el => el.textContent = "--");
    const quickStats = document.getElementById("dashboard-quick-stats");
    if (quickStats) quickStats.innerHTML = "";
    // Reset KPI values
    document.querySelectorAll(".kpi-value").forEach(el => el.textContent = "–");
  }
  document.body.classList.toggle("is-authenticated", isAuth);
  if (accountPillEl) accountPillEl.hidden = !isAuth;

  if (accountLabelEl) accountLabelEl.textContent = isAuth ? resolveDisplayName(account) : t("account_guest");
  if (accountStatusTagEl) accountStatusTagEl.textContent = isAuth ? t("account_signed_in") : t("account_guest");
  if (accountStatusCopyEl) {
    accountStatusCopyEl.textContent = isAuth
      ? t("account_status_signed_in")
      : t("account_status_guest");
  }
  const topAuthActionsVisible = !isAuth && activeAppView === "home";
  if (accountLoginBtn) accountLoginBtn.hidden = !topAuthActionsVisible;
  if (accountRegisterBtn) accountRegisterBtn.hidden = !topAuthActionsVisible;
  if (accountLogoutBtn) accountLogoutBtn.hidden = !isAuth;
  const athletesHeaderBtn = document.getElementById("athletes-header-btn");
  if (athletesHeaderBtn) athletesHeaderBtn.hidden = !isAuth;
  // Hide Training / peakplan. / Profil nav when not logged in — they're meaningless on the landing page
  if (accountHomeBtn) accountHomeBtn.hidden = !isAuth;
  if (accountProfileBtn) accountProfileBtn.hidden = !isAuth;
  const peakplanBtn = document.getElementById("account-peakplan-btn");
  if (peakplanBtn) peakplanBtn.hidden = !isAuth;
  _safeRender("renderAthletesDrawer", () => renderAthletesDrawer(account));
  if (accountOpenLoginBtn) accountOpenLoginBtn.hidden = true;
  if (accountOpenRegisterBtn) accountOpenRegisterBtn.hidden = true;
  if (savePlanBtn) savePlanBtn.disabled = !isAuth || !latestPlan || !latestProfile;
  _safeRender("renderProfileAvatar", () => renderProfileAvatar(account));
  populateSettingsForms(account);

  // Pre-populate plan form from saved input data
  populatePlanFormFromSaved(account);

  _safeRender("renderSavedPlansList", () => renderSavedPlansList(account));
  _safeRender("renderFriendsList", () => renderFriendsList(account));
  _safeRender("renderAccountSearchResults", () => renderAccountSearchResults(lastAccountSearchQuery));
  _safeRender("renderProfileStats", () => renderProfileStats(account));
  _safeRender("renderProfileFeed", () => renderProfileFeed(account));
  if (activeProfileView === "activities") _safeRender("renderActivityFeed", () => renderActivityFeed());
  _safeRender("renderCrewFeed", () => renderCrewFeed(account));
  _safeRender("renderCrewRanking", () => renderCrewRanking(account));
  _safeRender("renderHomeFeed", () => renderHomeFeed(account));
  _safeRender("renderFitnessAnalysis", () => renderFitnessAnalysis(account));
  _safeRender("renderDashboardRings", () => renderDashboardRings());
  _safeRender("renderDashboardKpis", () => renderDashboardKpis(account));
  _safeRender("renderFitnessAgeHighlight", () => renderFitnessAgeHighlight(account));
  // Show predictions from activity data if no plan is loaded
  _safeRender("predictions", () => {
    if (!latestProfile && account?.activities?.length) {
      const analysis = analyzeActivityHistory(account.activities);
      if (analysis?.runPbs?.length) {
        const pbMap = {};
        for (const pb of analysis.runPbs) pbMap[pb.distance] = pb;
        function secToHMS(sec) {
          if (!sec) return "";
          const h = Math.floor(sec / 3600);
          const m = Math.floor((sec % 3600) / 60);
          const s = Math.round(sec % 60);
          return `${h}:${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")}`;
        }
        const pb1 = pbMap["10k"] || pbMap["half"] || pbMap["5k"] || analysis.runPbs[0];
        const pb2 = pbMap["half"] || pbMap["marathon"] || (pb1 !== pbMap["10k"] ? pbMap["10k"] : null);
        const activityProfile = {
          discipline: "running",
          pb1Distance: pb1?.distance || "10k",
          pb1Time: secToHMS(pb1?.timeSec),
          pb2Distance: pb2?.distance === "half" ? "half" : pb2?.distance || "",
          pb2Time: pb2 ? secToHMS(pb2.timeSec) : "",
          sex: account.settings?.account?.sex || "male",
          age: Number(account.settings?.account?.age) || 35,
          weeklyKm: analysis.weeklyVolume?.distanceKm || 40,
          runsPerWeek: analysis.weeklyVolume?.sessions || 3,
          fitnessLevel: analysis.weeklyVolume?.distanceKm > 60 ? "advanced" : analysis.weeklyVolume?.distanceKm > 30 ? "intermediate" : "starter",
        };
        renderProfilePredictions(activityProfile, null);
      }
    } else if (latestProfile) {
      renderProfilePredictions(latestProfile, latestPlan);
    }
  });
  setActiveAccountSection(activeAccountSection);
  syncProfileComposerVisibility();
  _safeRender("renderStravaProfileStatus", () => renderStravaProfileStatus(account));
  _safeRender("updateConnectionStateCopy", () => updateConnectionStateCopy());
  _safeRender("maybeFetchStravaStatus", () => maybeFetchStravaStatus(account));
}

function populateSettingsForms(account) {
  if (!account) {
    [accountSettingsFormEl, privacySettingsFormEl, safetySettingsFormEl].forEach((formEl) => formEl?.reset());
    return;
  }
  ensureAccountSettingsShape(account);
  const settings = account.settings;
  setFormValue(accountSettingsFormEl, "language", settings.account.language);
  setFormValue(accountSettingsFormEl, "units", settings.account.units);
  setFormValue(accountSettingsFormEl, "timezone", settings.account.timezone);
  setFormValue(accountSettingsFormEl, "emailNotifications", settings.account.emailNotifications);
  setFormValue(privacySettingsFormEl, "profileVisibility", settings.privacy.profileVisibility);
  setFormValue(privacySettingsFormEl, "activityVisibility", settings.privacy.activityVisibility);
  setFormValue(privacySettingsFormEl, "searchDiscoverability", settings.privacy.searchDiscoverability);
  setFormValue(privacySettingsFormEl, "messagingPermission", settings.privacy.messagingPermission);
  setFormValue(privacySettingsFormEl, "mapPrivacy", settings.privacy.mapPrivacy);
  setFormValue(privacySettingsFormEl, "mentionsPermission", settings.privacy.mentionsPermission);
  setFormValue(safetySettingsFormEl, "commentFilter", settings.safety.commentFilter);
  setFormValue(safetySettingsFormEl, "imageModeration", settings.safety.imageModeration);
  setFormValue(safetySettingsFormEl, "riskWarnings", settings.safety.riskWarnings);
  setFormValue(safetySettingsFormEl, "communityGuidelinesAccepted", settings.safety.communityGuidelinesAccepted);

  // BUG 5: Populate new display fields
  setFormValue(accountSettingsFormEl, "distanceUnit", settings.account.distanceUnit);
  setFormValue(accountSettingsFormEl, "paceFormat", settings.account.paceFormat);
  setFormValue(accountSettingsFormEl, "elevationUnit", settings.account.elevationUnit);
  setFormValue(accountSettingsFormEl, "weightUnit", settings.account.weightUnit);
  setFormValue(accountSettingsFormEl, "weekStart", settings.account.weekStart);

  // BUG 2: Populate profile settings form
  const profileForm = document.getElementById("profile-settings-form");
  if (profileForm && account.profile) {
    setFormValue(profileForm, "displayName", account.profile.displayName);
    setFormValue(profileForm, "bio", account.profile.bio);
    setFormValue(profileForm, "sex", account.profile.sex);
    setFormValue(profileForm, "birthYear", account.profile.birthYear);
    setFormValue(profileForm, "weight", account.profile.weight);
    setFormValue(profileForm, "height", account.profile.height);
    setFormValue(profileForm, "restingHr", account.profile.restingHr);
    setFormValue(profileForm, "maxHr", account.profile.maxHr);
  }
  // Sport checkboxes
  const sports = account.settings?.sports || {};
  ["sport-running", "sport-cycling", "sport-swimming", "sport-triathlon", "sport-hyrox", "sport-gym", "sport-yoga", "sport-hiking"].forEach((name) => {
    const cb = profileForm?.elements?.[name];
    if (cb) cb.checked = !!sports[name];
  });

  // BUG 4: Populate data source selects
  const healthSrc = document.getElementById("health-data-source-select");
  if (healthSrc && account?.settings?.healthDataSource) healthSrc.value = account.settings.healthDataSource;
  const actSrc = document.getElementById("activity-data-source-select");
  if (actSrc && account?.settings?.activityDataSource) actSrc.value = account.settings.activityDataSource;

  // BUG 6: Restore notification checkbox state
  const notifs = account.settings?.notifications || {};
  ["notif-push", "notif-email", "notif-social"].forEach(id => {
    const cb = document.getElementById(id);
    if (cb && notifs[id] !== undefined) cb.checked = notifs[id];
  });

  // Populate Eingabedaten display in settings
  populateInputDataDisplay(account);
}

function setFormValue(formEl, name, value) {
  const field = formEl?.elements?.[name];
  if (field) field.value = value ?? "";
}

function renderSavedPlansList(account) {
  const plans = account?.plans || [];
  if (savedPlanCountEl) savedPlanCountEl.textContent = String(plans.length);
  if (!savedPlansListEl) return;
  if (!plans.length) {
    savedPlansListEl.innerHTML = `<div class="empty-copy">${escapeHtml(t("empty_saved_plans"))}</div>`;
    return;
  }
  savedPlansListEl.innerHTML = plans
    .map(
      (plan) => `
      <div class="saved-plan-item">
        <strong>${escapeHtml(plan.title)}</strong>
        <small>${escapeHtml(plan.summary)} • ${escapeHtml(formatDateShort(new Date(plan.createdAt)))}</small>
        <div class="saved-plan-actions">
          <button type="button" class="ghost" data-load-plan-id="${escapeHtml(plan.id)}">${escapeHtml(currentLang === "ja" ? "プランを開く" : currentLang === "en" ? "Load plan" : "Plan laden")}</button>
          <button type="button" class="ghost danger" data-delete-plan-id="${escapeHtml(plan.id)}">Löschen</button>
        </div>
      </div>`
    )
    .join("");

  // Delegated plan button listeners (once)
  if (!savedPlansListEl._delegated) {
    savedPlansListEl._delegated = true;
    savedPlansListEl.addEventListener("click", (e) => {
      const loadBtn = e.target.closest("[data-load-plan-id]");
      if (loadBtn) { loadSavedPlanById(loadBtn.getAttribute("data-load-plan-id")); return; }
      const delBtn = e.target.closest("[data-delete-plan-id]");
      if (delBtn) {
        const planId = delBtn.getAttribute("data-delete-plan-id");
        const account = getCurrentAccount();
        if (!account) return;
        const plan = (account.plans || []).find((p) => p.id === planId);
        const title = plan?.title || plan?.summary || "dieser Plan";
        if (!window.confirm(`Plan "${title}" wirklich löschen?`)) return;
        account.plans = (account.plans || []).filter((p) => p.id !== planId);
        persistStore();
        renderSavedPlansList(account);
        if (window.sbDb && planId) {
          sbDb.deletePlan(planId).catch((e) => console.warn("[deletePlan] Supabase:", e?.message || e));
        }
      }
    });
  }
}

function renderFriendsList(account) {
  const friends = account?.friends || [];
  if (!friendsListEl) return;
  if (!friends.length) {
    friendsListEl.innerHTML = `<div class="empty-copy">${escapeHtml(t("empty_connections"))}</div>`;
    return;
  }
  friendsListEl.innerHTML = friends
    .map((email) => {
      const friend = (appStore.accounts || []).find((a) => a.email === email);
      const stats = computeAccountStats(friend);
      const latest = (friend?.activities || [])[0];
      const latestText = latest
        ? `${latest.kind === "race" ? "race." : t("label_training")} • ${formatSocialSportLabel(latest.sportType)}${latest.distanceKm ? ` • ${Number(latest.distanceKm).toFixed(1)} km` : ""}`
        : t("label_no_activity");
      return `
      <div class="friend-item">
        <strong>${escapeHtml(email)}</strong>
        <small>${stats.points} ${escapeHtml(t("unit_points"))} • ${stats.races} ${escapeHtml(t("unit_races"))} • ${escapeHtml(latestText)}</small>
      </div>`
    })
    .join("");
}

// In-memory cache of the last remote search (avoids duplicate Supabase calls)
let _remoteSearchSeq = 0;
let _remoteFriendships = null; // {friendIds:Set, pendingOut:Set, pendingIn:Set, byId:Map}

async function loadRemoteFriendships() {
  try {
    const user = await (window.sbAuth?.getUser?.() || Promise.resolve(null));
    if (!user?.id || !window.sbDb?.getAllFriendships) return null;
    const rows = await window.sbDb.getAllFriendships(user.id);
    const friendIds = new Set(), pendingOut = new Set(), pendingIn = new Set();
    const byId = new Map();
    rows.forEach((r) => {
      byId.set(`${r.user_id}:${r.friend_id}`, r);
      if (r.status === "accepted") {
        if (r.user_id === user.id) friendIds.add(r.friend_id);
        else friendIds.add(r.user_id);
      } else if (r.status === "pending") {
        if (r.user_id === user.id) pendingOut.add(r.friend_id);
        else pendingIn.add(r.user_id);
      }
    });
    _remoteFriendships = { friendIds, pendingOut, pendingIn, byId, selfId: user.id };
    return _remoteFriendships;
  } catch (e) {
    console.warn("[loadRemoteFriendships]", e);
    return null;
  }
}

async function sendConnectRequest(targetUserId) {
  const self = await (window.sbAuth?.getUser?.() || Promise.resolve(null));
  if (!self?.id) { openAccountModal("login"); return { ok: false }; }
  try {
    await window.sbDb.sendFriendRequest(self.id, targetUserId);
    _remoteFriendships = null; // invalidate
    return { ok: true };
  } catch (e) {
    console.warn("[sendConnectRequest]", e);
    return { ok: false, error: e?.message || "Konnte Anfrage nicht senden" };
  }
}

async function acceptConnectRequest(rowId) {
  try {
    await window.sbDb.acceptFriendRequest(rowId);
    _remoteFriendships = null;
    return { ok: true };
  } catch (e) { return { ok: false, error: e?.message }; }
}

function renderAccountSearchResults(query = "") {
  if (!accountSearchResultsEl) return;
  const q = String(query || "").trim();
  const account = getCurrentAccount();
  const ownEmail = account?.email || "";

  if (!q) {
    if (crewResultCountEl) crewResultCountEl.textContent = "0";
    // Instead of empty-prompt, show directory of recent users when query is blank
    accountSearchResultsEl.innerHTML = `<div class="empty-copy">${escapeHtml(t("empty_search_prompt"))}</div>`;
    if (window.sbDb?.listPublicProfiles) {
      const seq = ++_remoteSearchSeq;
      (async () => {
        const [profiles, friendships] = await Promise.all([
          window.sbDb.listPublicProfiles(24).catch(() => []),
          loadRemoteFriendships(),
        ]);
        if (seq !== _remoteSearchSeq) return;
        renderSearchRows(profiles.filter((p) => p.email !== ownEmail), friendships, { mode: "directory" });
      })();
    }
    return;
  }

  accountSearchResultsEl.innerHTML = `<div class="empty-copy">${escapeHtml(t("searching") || "Suche …")}</div>`;
  const seq = ++_remoteSearchSeq;

  (async () => {
    const [remote, friendships] = await Promise.all([
      window.sbDb?.searchUsers ? window.sbDb.searchUsers(q, 20).catch(() => []) : Promise.resolve([]),
      loadRemoteFriendships(),
    ]);
    if (seq !== _remoteSearchSeq) return;

    // Merge with local accounts (fallback for offline / pre-Supabase users)
    const local = (appStore?.accounts || [])
      .filter((a) => a.email !== ownEmail)
      .filter((a) => {
        const lo = q.toLowerCase();
        return a.email?.toLowerCase().includes(lo) || (a.displayName || a.email || "").toLowerCase().includes(lo);
      })
      .map((a) => ({ id: a.email, email: a.email, display_name: a.displayName || a.email.split("@")[0], _local: true }));

    // De-dup by email
    const seen = new Set();
    const merged = [];
    remote.filter((r) => r.email !== ownEmail).forEach((r) => {
      if (seen.has(r.email)) return;
      seen.add(r.email);
      merged.push(r);
    });
    local.forEach((l) => { if (!seen.has(l.email)) { seen.add(l.email); merged.push(l); } });

    if (crewResultCountEl) crewResultCountEl.textContent = String(merged.length);
    if (!merged.length) {
      accountSearchResultsEl.innerHTML = `<div class="empty-copy">${escapeHtml(t("empty_search_none"))}</div>`;
      return;
    }
    renderSearchRows(merged, friendships, { mode: "search" });
  })();
}

function renderSearchRows(list, friendships, opts = {}) {
  const account = getCurrentAccount();
  accountSearchResultsEl.innerHTML = (list || []).map((u) => {
    const name = u.display_name || (u.email ? u.email.split("@")[0] : "Athlete");
    const isRemote = !u._local;
    const isFriend = friendships?.friendIds?.has(u.id);
    const isPendingOut = friendships?.pendingOut?.has(u.id);
    const isPendingIn = friendships?.pendingIn?.has(u.id);
    const legacyFriend = Boolean(account?.friends?.includes(u.email));
    const connected = isFriend || legacyFriend;
    const btnLabel = connected ? (t("connected") || "Verbunden")
      : isPendingOut ? "Angefragt"
      : isPendingIn ? "Akzeptieren"
      : (t("connect") || "Verbinden");
    const btnAction = isPendingIn ? "accept" : connected ? "none" : "request";
    const disabled = connected || isPendingOut;
    const avatar = u.profile_image
      ? `<img src="${escapeHtml(u.profile_image)}" alt="" style="width:38px;height:38px;border-radius:50%;object-fit:cover;">`
      : `<div style="width:38px;height:38px;border-radius:50%;background:linear-gradient(135deg,#3b82f6,#8b5cf6);display:flex;align-items:center;justify-content:center;color:#fff;font-weight:700;font-size:15px;">${escapeHtml(name.charAt(0).toUpperCase())}</div>`;
    return `
      <div class="account-search-item">
        <div class="account-search-row" style="display:flex;gap:12px;align-items:center;">
          ${avatar}
          <div style="flex:1;min-width:0;">
            <strong>${escapeHtml(name)}</strong>
            ${!isRemote ? `<small style="display:block;color:#94a3b8;">lokal</small>` : ""}
          </div>
          <div class="account-search-actions">
            <button type="button" class="ghost"
              data-connect-user-id="${escapeHtml(String(u.id))}"
              data-connect-user-email="${escapeHtml(u.email || "")}"
              data-connect-action="${btnAction}"
              data-connect-row-id="${escapeHtml(String(friendships?.byId?.get(`${u.id}:${friendships?.selfId}`)?.id || ""))}"
              ${disabled ? "disabled" : ""}>
              ${escapeHtml(btnLabel)}
            </button>
          </div>
        </div>
      </div>`;
  }).join("");

  accountSearchResultsEl.querySelectorAll("[data-connect-user-id]").forEach((btn) => {
    btn.addEventListener("click", async () => {
      const action = btn.dataset.connectAction;
      const userId = btn.dataset.connectUserId;
      const email = btn.dataset.connectUserEmail;
      if (action === "none") return;
      btn.disabled = true;
      btn.textContent = "…";
      try {
        if (action === "request") {
          // Use Supabase if target has a UUID (remote), else fall back to local
          const isUuid = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(userId);
          if (isUuid) {
            const r = await sendConnectRequest(userId);
            if (!r.ok) throw new Error(r.error || "Anfrage fehlgeschlagen");
          } else {
            // Legacy local friendship by email
            const current = getCurrentAccount();
            if (!current) { openAccountModal("login"); return; }
            const r = addFriendByEmail(current, email);
            if (r.ok) persistStore();
          }
        } else if (action === "accept") {
          const rowId = btn.dataset.connectRowId;
          if (rowId) await acceptConnectRequest(rowId);
        }
        // Refresh view
        const input = document.querySelector("[data-account-search-input]");
        renderAccountSearchResults(input?.value || "");
      } catch (e) {
        console.warn("[connect]", e);
        btn.disabled = false;
        btn.textContent = "Fehler – erneut";
      }
    });
  });
}

function setActiveAccountSection(section) {
  activeAccountSection = section === "crew" ? "crew" : "profile";
  accountSectionTabButtons.forEach((btn) =>
    btn.classList.toggle("is-active", btn.dataset.accountSection === activeAccountSection)
  );
  if (accountPaneProfileEl) accountPaneProfileEl.classList.toggle("is-active", activeAccountSection === "profile");
  if (accountPaneCrewEl) accountPaneCrewEl.classList.toggle("is-active", activeAccountSection === "crew");
}

function setActiveProfileView(view) {
  activeProfileView = ["overview", "playbook", "statistics", "activities", "settings"].includes(view) ? view : "overview";
  persistUiState();
  document.body.classList.remove("profile-view-overview", "profile-view-playbook", "profile-view-statistics", "profile-view-activities", "profile-view-settings");
  document.body.classList.add(`profile-view-${activeProfileView}`);
  profileViewTabButtons.forEach((btn) => btn.classList.toggle("is-active", btn.dataset.profileView === activeProfileView));
  // Keep top-nav Training button state in sync with sub-view changes
  accountHomeBtn?.classList.toggle("is-active", activeAppView === "profile" && activeProfileView !== "playbook");
  if (activeProfileView === "settings") {
    setActiveProfileSettingsView(activeProfileSettingsView || "profile");
  }
  if (activeProfileView === "overview") {
    maybeFetchStravaStatus(getCurrentAccount());
    _safeRender("renderDashboardRings", () => renderDashboardRings());
    _safeRender("renderDashboardKpis", () => renderDashboardKpis(getCurrentAccount()));
    _safeRender("renderFitnessAgeHighlight", () => renderFitnessAgeHighlight(getCurrentAccount()));
    const _ov = normalizeActivities(getCurrentAccount()?.activities || []);
    _safeRender("renderLoadChart", () => renderLoadChart(_ov));
    _safeRender("renderConsistencyChart", () => renderConsistencyChart(_ov));
  }
  if (activeProfileView === "statistics") _safeRender("renderStatisticsView", () => renderStatisticsView(getCurrentAccount()));
  if (activeProfileView === "activities") _safeRender("renderActivityFeed", () => renderActivityFeed());
  if (activeProfileView === "playbook") populatePlanFormFromSaved(getCurrentAccount());

  // Move plan form + results into/out of Playbook host
  syncPlaybookFormPlacement();

  if (activeAppView === "profile") {
    scrollToSectionStart(sectionAccountEl, { mobileOffset: 72, desktopOffset: 64, duration: 360 });
  }
}

function syncPlaybookFormPlacement() {
  const playbookFormHost = document.getElementById("playbook-form-host");
  const playbookResultsHost = document.getElementById("playbook-results-host");
  const planForm = document.getElementById("plan-form");
  const calendarSection = document.querySelector(".section-calendar");
  const landingPanel = document.querySelector(".landing-panel");
  const calendarCard = document.querySelector(".result-calendar-card");

  if (!playbookFormHost || !planForm) return;

  if (activeProfileView === "playbook" && getCurrentAccount()) {
    // Move form into Playbook
    if (planForm.parentElement !== playbookFormHost) {
      playbookFormHost.appendChild(planForm);
    }
    // Move calendar results into Playbook
    if (calendarCard && playbookResultsHost && calendarCard.parentElement !== playbookResultsHost) {
      playbookResultsHost.appendChild(calendarCard);
    }
    // Show plan results section if plan exists
    const resultsSection = document.getElementById("profile-card-plan-results");
    if (resultsSection) resultsSection.hidden = !generatedSessions.length;
  } else {
    // Move form back to landing panel
    if (landingPanel && planForm.parentElement !== landingPanel) {
      landingPanel.appendChild(planForm);
    }
    // Move calendar results back
    if (calendarCard && calendarSection && calendarCard.parentElement !== calendarSection) {
      calendarSection.appendChild(calendarCard);
    }
  }
}

function setActiveProfileSettingsView(view) {
  activeProfileSettingsView = ["profile", "connections", "privacy", "notifications", "display", "security", "safety", "data"].includes(view) ? view : "profile";
  persistUiState();
  profileSettingsNavButtons.forEach((btn) =>
    btn.classList.toggle("is-active", btn.dataset.profileSettingsView === activeProfileSettingsView)
  );
  profileSettingsPanels.forEach((panel) =>
    panel.classList.toggle("is-active", panel.dataset.profileSettingsPanel === activeProfileSettingsView)
  );
}

function setAppView(view) {
  activeAppView = ["home", "profile"].includes(view) ? view : "home";
  persistUiState();
  document.body.classList.remove("app-view-home", "app-view-profile", "app-view-crew");
  document.body.classList.add(`app-view-${activeAppView}`);

  const isAuth = Boolean(getCurrentAccount());
  const peakplanMode = document.body.classList.contains("peakplan-mode");
  // When logged in and on Home, show feed instead of landing page (unless peakplan-mode overrides)
  document.body.classList.toggle("home-feed-mode", isAuth && activeAppView === "home" && !peakplanMode);

  // Swapped: "Home" button active when on workspace (profile view), "Profil" button active when on public/home view
  // Training button active when in profile (excluding playbook sub-view)
  accountHomeBtn?.classList.toggle("is-active", !peakplanMode && activeAppView === "profile" && activeProfileView !== "playbook");
  // Profil button active when on home (public profile + feed)
  accountProfileBtn?.classList.toggle("is-active", !peakplanMode && activeAppView === "home");
  // peakplan. CTA active when in peakplan-mode
  document.getElementById("account-peakplan-btn")?.classList.toggle("is-active", peakplanMode);

  const homeFeedSection = document.getElementById("home-feed-section");
  if (homeFeedSection) homeFeedSection.hidden = !(isAuth && activeAppView === "home" && !peakplanMode);
  const publicProfileSection = document.getElementById("public-profile-section");
  if (publicProfileSection) publicProfileSection.hidden = !(isAuth && activeAppView === "home" && !peakplanMode);
  if (isAuth && activeAppView === "home" && !peakplanMode && window.PublicProfile?.render) {
    try { window.PublicProfile.render(); } catch (e) { console.warn("[PublicProfile] render:", e); }
  }

  if (activeAppView === "profile") {
    setActiveProfileView(activeProfileView);
    sectionAccountEl?.classList.add("is-visible");
    sectionDataEl?.classList.add("is-visible");
  } else {
    document.body.classList.remove("profile-view-overview", "profile-view-playbook", "profile-view-statistics", "profile-view-activities", "profile-view-settings");
    syncPlaybookFormPlacement(); // move form back to landing when leaving profile
  }
  window.scrollTo({ top: 0, behavior: "smooth" });
  renderAccountUi();
}

function renderProfileAvatar(account) {
  if (!profileAvatarPreviewEl) return;
  const label = (account?.email?.[0] || "A").toUpperCase();
  profileAvatarPreviewEl.textContent = label;
  if (account?.profileImage) {
    profileAvatarPreviewEl.style.backgroundImage = `url('${account.profileImage}')`;
    profileAvatarPreviewEl.classList.add("has-image");
  } else {
    profileAvatarPreviewEl.style.backgroundImage = "";
    profileAvatarPreviewEl.classList.remove("has-image");
  }
  // Also sync the settings-panel avatar preview
  try { syncSettingsAvatarPreview(); } catch (_) {}
}

function postActivity(account, { title, note, kind, sportType, distanceKm, imageDataUrl }) {
  account.activities = Array.isArray(account.activities) ? account.activities : [];
  const validSport = ["run", "bike", "swim", "hyrox", "other"].includes(sportType) ? sportType : "other";
  const dist = clamp(Number(distanceKm) || 0, 0, 1000);
  const activity = {
    id: `act_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
    createdAt: new Date().toISOString(),
    title,
    note,
    kind,
    sportType: validSport,
    distanceKm: dist,
    imageDataUrl: imageDataUrl || null,
    propsBy: [],
  };
  account.activities.unshift(activity);

  // Sync to Supabase in background
  if (typeof sbDb !== "undefined" && account.id && !account.id.startsWith("acc_")) {
    sbDb.postActivity(account.id, {
      title, note, kind, sport_type: validSport, distance_km: dist, image_url: imageDataUrl || null,
    }).then((saved) => { if (saved?.id) activity.id = saved.id; })
      .catch((e) => console.warn("Activity sync error:", e));
  }
}

function renderProfileStats(account) {
  const statsToday = computeAccountStats(account, { range: "today" });
  const statsYear = computeAccountStats(account, { range: "12m" });
  const statsAll = computeAccountStats(account, { range: "all" });
  if (profilePointsBadgeEl) profilePointsBadgeEl.textContent = `${statsAll.points} ${t("unit_points")}`;
  applyProfileStatsToBindings(profileStatBindings.today, statsToday);
  applyProfileStatsToBindings(profileStatBindings.year, statsYear);
  applyProfileStatsToBindings(profileStatBindings.all, statsAll);
}

function renderProfilePredictions(profile, plan) {
  const card = document.getElementById("profile-card-predictions");
  if (!card) return;

  if (!profile) { card.hidden = true; return; }

  // Build a minimal "last" object from plan projection for predictions
  const series = plan ? getActualPerformanceSeries(profile, plan) : null;
  const last = series && series.length
    ? series[series.length - 1]
    : { fitness: 50, fatigue: 45, freshness: 52, readiness: 58, vo2: vdotFromProfile(profile) || 40 };

  const predictions = buildRacePredictions(profile, last, plan || {});
  if (!predictions || !predictions.labels) { card.hidden = true; return; }

  card.hidden = false;

  // VO2max and Fitness Age
  const vo2maxResult = estimateVO2max(profile);
  setText(document.getElementById("profile-vo2max"), vo2maxResult.value);
  const chronoAge = Number(profile?.age) || null;
  const fitnessAge = estimateFitnessAge(vo2maxResult.value, profile?.sex, chronoAge);
  setText(document.getElementById("profile-fitness-age"), fitnessAge != null ? fitnessAge : "-");
  const fitAgeDelta = document.getElementById("profile-fitness-age-delta");
  const fitAgeStrong = document.getElementById("profile-fitness-age");
  if (fitAgeDelta && fitnessAge != null && chronoAge) {
    const diff = chronoAge - fitnessAge;
    if (diff > 0) { fitAgeDelta.textContent = `${diff} J. jünger`; fitAgeDelta.style.color = "var(--accent-fresh)"; }
    else if (diff < 0) { fitAgeDelta.textContent = `${Math.abs(diff)} J. älter`; fitAgeDelta.style.color = "var(--accent-fatigue)"; }
    else { fitAgeDelta.textContent = "Durchschnitt"; fitAgeDelta.style.color = "var(--muted)"; }
  } else if (fitAgeDelta) {
    fitAgeDelta.textContent = "";
  }
  // Color Fitness Age only when comparison is possible
  if (fitAgeStrong) {
    fitAgeStrong.style.color = chronoAge ? (chronoAge > fitnessAge ? "var(--accent-fresh)" : chronoAge < fitnessAge ? "var(--accent-fatigue)" : "#fff") : "#fff";
  }

  // VDOT tag removed — not user-relevant

  // Current predictions
  const labels = predictions.labels;
  const values = predictions.values;
  setText(document.getElementById("profile-pred-label-a"), labels.a);
  setText(document.getElementById("profile-pred-label-b"), labels.b);
  setText(document.getElementById("profile-pred-label-c"), labels.c);
  setText(document.getElementById("profile-pred-label-d"), labels.d);
  setText(document.getElementById("profile-pred-a"), values.a);
  setText(document.getElementById("profile-pred-b"), values.b);
  setText(document.getElementById("profile-pred-c"), values.c);
  setText(document.getElementById("profile-pred-d"), values.d);

  // Race-day projections
  const rdCol = document.getElementById("predictions-raceday-col");
  if (predictions.raceDayValues && rdCol) {
    rdCol.hidden = false;
    setText(document.getElementById("profile-pred-rd-a"), predictions.raceDayValues.a);
    setText(document.getElementById("profile-pred-rd-b"), predictions.raceDayValues.b);
    setText(document.getElementById("profile-pred-rd-c"), predictions.raceDayValues.c);
    setText(document.getElementById("profile-pred-rd-d"), predictions.raceDayValues.d);
    const noteEl = document.getElementById("predictions-raceday-note");
    if (noteEl) {
      const raceDateStr = profile.raceDate ? new Date(profile.raceDate).toLocaleDateString("de-DE", { day: "numeric", month: "short", year: "numeric" }) : "";
      noteEl.textContent = raceDateStr ? `Prognose für ${raceDateStr} — basierend auf deinem Trainingsplan.` : "Basierend auf deinem Trainingsplan.";
    }
  } else if (rdCol) {
    rdCol.hidden = true;
  }

  // Adaptive status — user-friendly German labels
  const adaptStatusEl = document.getElementById("predictions-adaptive-status");
  if (adaptStatusEl && plan?.meta?.adaptiveSignals) {
    const signals = plan.meta.adaptiveSignals;
    const parts = [];
    const compMap = { excellent: "Sehr gut umgesetzt", good: "Gut umgesetzt", partial: "Teilweise umgesetzt", low: "Wenig umgesetzt" };
    const trajMap = { ahead: "Über Plan", on_track: "Im Plan", behind: "Unter Plan", breakthrough: "Starker Fortschritt" };
    const fatMap = { elevated: "Erhöhte Belastung", high: "Hohe Belastung", critical: "Erholung nötig" };
    const adjMap = { deload: "Entlastungswoche", rebuild: "Aufbauwoche", push: "Steigerung", downgrade: "Anpassung" };
    if (signals.complianceLabel && signals.complianceLabel !== "No data") {
      const cl = compMap[signals.complianceLabel] || null;
      if (cl) parts.push(cl);
    }
    if (signals.trajectoryLabel) {
      const tl = trajMap[signals.trajectoryLabel] || null;
      if (tl) parts.push(tl);
    }
    if (signals.fatigueRisk && signals.fatigueRisk !== "optimal") {
      const fl = fatMap[signals.fatigueRisk] || null;
      if (fl) parts.push(fl);
    }
    if (signals.adjustmentType && signals.adjustmentType !== "none") {
      const al = adjMap[signals.adjustmentType] || null;
      if (al) parts.push(al);
    }
    if (parts.length) {
      adaptStatusEl.hidden = false;
      adaptStatusEl.textContent = parts.join(" · ");
    } else {
      adaptStatusEl.hidden = true;
    }
  } else if (adaptStatusEl) {
    adaptStatusEl.hidden = true;
  }
}

function renderFitnessAnalysis(account) {
  const bodyEl = document.getElementById("fitness-analysis-body");
  const sourceEl = document.getElementById("fitness-analysis-source");
  if (!bodyEl) return;

  const activities = account?.activities;
  if (!Array.isArray(activities) || !activities.length) {
    if (sourceEl) sourceEl.textContent = "–";
    bodyEl.innerHTML = `<p class="card-copy">Verbinde Strava, Garmin oder WHOOP um deine Fitness automatisch zu analysieren.</p>`;
    return;
  }

  const analysis = analyzeActivityHistory(activities);
  if (!analysis) return;

  const sources = new Set(activities.map((a) => a.source).filter(Boolean));
  if (sourceEl) sourceEl.textContent = [...sources].join(", ") || "Daten";

  const rows = [];

  // PBs
  if (analysis.runPbs?.length) {
    const pbHtml = analysis.runPbs.map((pb) =>
      `<div class="fitness-metric"><span class="fitness-metric-label">${pb.distance.toUpperCase()}</span><strong class="fitness-metric-value">${escapeHtml(pb.timeFormatted)}</strong></div>`
    ).join("");
    rows.push(`<div class="fitness-section"><h5>Bestzeiten (Auto-Detect)</h5><div class="fitness-metrics-row">${pbHtml}</div></div>`);
  }

  // Training Load
  if (analysis.trainingLoad) {
    const tl = analysis.trainingLoad;
    const acwr = tl.acwr;
    const acwrClass = acwr < 0.8 ? "low" : acwr <= 1.3 ? "optimal" : "high";
    const acwrLabel = acwr < 0.8 ? "Unterbelastet" : acwr <= 1.3 ? "Sweet Spot" : "Überlastrisiko";
    rows.push(`<div class="fitness-section"><h5>Trainingsbelastung</h5><div class="fitness-metrics-row">
      <div class="fitness-metric"><span class="fitness-metric-label">Akut (7d)</span><strong class="fitness-metric-value">${tl.acuteLoad7d}</strong></div>
      <div class="fitness-metric"><span class="fitness-metric-label">Chronisch (28d)</span><strong class="fitness-metric-value">${tl.chronicLoad28d}</strong></div>
      <div class="fitness-metric"><span class="fitness-metric-label">ACWR</span><strong class="fitness-metric-value acwr-${acwrClass}">${acwr}</strong><span class="fitness-metric-hint">${acwrLabel}</span></div>
    </div></div>`);
  }

  // Weekly Volume
  if (analysis.weeklyVolume) {
    const wv = analysis.weeklyVolume;
    rows.push(`<div class="fitness-section"><h5>Wochenvolumen (Ø ${wv.weeksAnalyzed} Wochen)</h5><div class="fitness-metrics-row">
      <div class="fitness-metric"><span class="fitness-metric-label">Distanz</span><strong class="fitness-metric-value">${wv.avgWeeklyKm} km</strong></div>
      <div class="fitness-metric"><span class="fitness-metric-label">Stunden</span><strong class="fitness-metric-value">${wv.avgWeeklyHours}h</strong></div>
      <div class="fitness-metric"><span class="fitness-metric-label">Sessions</span><strong class="fitness-metric-value">${wv.avgWeeklySessions}</strong></div>
    </div></div>`);
  }

  // HR Profile
  if (analysis.hrProfile) {
    const hr = analysis.hrProfile;
    rows.push(`<div class="fitness-section"><h5>Herzfrequenz-Profil</h5><div class="fitness-metrics-row">
      <div class="fitness-metric"><span class="fitness-metric-label">Max HR</span><strong class="fitness-metric-value">${hr.maxHr} bpm</strong></div>
      <div class="fitness-metric"><span class="fitness-metric-label">Schwelle (est.)</span><strong class="fitness-metric-value">${hr.estimatedThresholdHr} bpm</strong></div>
      <div class="fitness-metric"><span class="fitness-metric-label">Samples</span><strong class="fitness-metric-value">${hr.sampleSize}</strong></div>
    </div></div>`);
  }

  // FTP
  if (analysis.estimatedFtp) {
    rows.push(`<div class="fitness-section"><h5>Rad-Leistung</h5><div class="fitness-metrics-row">
      <div class="fitness-metric"><span class="fitness-metric-label">FTP (est.)</span><strong class="fitness-metric-value">${analysis.estimatedFtp.ftp}W</strong><span class="fitness-metric-hint">${analysis.estimatedFtp.confidence} confidence</span></div>
    </div></div>`);
  }

  // Swim CSS
  if (analysis.swimCss) {
    rows.push(`<div class="fitness-section"><h5>Schwimmen</h5><div class="fitness-metrics-row">
      <div class="fitness-metric"><span class="fitness-metric-label">CSS</span><strong class="fitness-metric-value">${escapeHtml(analysis.swimCss.formatted)}/100m</strong></div>
    </div></div>`);
  }

  bodyEl.innerHTML = rows.length
    ? rows.join("")
    : `<p class="card-copy">Nicht genug Aktivitätsdaten für eine Analyse.</p>`;
}

function renderProfileFeed(account) {
  const activities = account?.activities || [];
  if (profileFeedCountEl) profileFeedCountEl.textContent = String(activities.length);
  if (!profileFeedListEl) return;
  if (!activities.length) {
    profileFeedListEl.innerHTML = `<div class="empty-copy">${escapeHtml(t("empty_profile_feed"))}</div>`;
    return;
  }
  profileFeedListEl.innerHTML = activities.map((item) => buildActivityCardHtml({
    item,
    actorEmail: account.email,
    actorName: resolveDisplayName(account),
    actorAvatar: account.profileImage || null,
    actorPoints: activityPoints(item),
    viewerEmail: account.email,
    showPropsAction: false,
  })).join("");
}

function renderActivityFeed() {
  const container = document.getElementById("activity-feed-container");
  if (!container) return;
  const account = getCurrentAccount();
  const activities = (account?.activities || []).slice(0, 30).sort((a, b) => new Date(b.createdAt || b.date || b.start_date || 0) - new Date(a.createdAt || a.date || a.start_date || 0));

  if (!activities.length) {
    container.innerHTML = '<div class="activity-feed-empty">Noch keine Aktivitaeten. Verbinde dein Geraet oder importiere Aktivitaeten.</div>';
    return;
  }

  const displayName = resolveDisplayName(account);
  const initials = (displayName[0] || "A").toUpperCase();
  const actorAvatar = account.profileImage || null;

  container.innerHTML = activities.map((item, _idx) => {
    const dateRaw = item.createdAt || item.date || item.start_date || item.start_date_local;
    const date = dateRaw ? new Date(dateRaw) : new Date();
    const dateValid = !isNaN(date.getTime());
    const dateStr = dateValid ? formatRelativeDate(date) : "";
    const timeStr = dateValid ? date.toLocaleTimeString("de-DE", { hour: "2-digit", minute: "2-digit" }) : "";
    const sportType = item.sportType || normalizeSportType(item.type, item.sport);
    const sportLabel = formatActivityFeedSportLabel(sportType);

    const distKm = item.distanceKm ? Number(item.distanceKm) : (item.distance ? Number(item.distance) / 1000 : null);
    const durationSec = item.movingTimeSec || item.moving_time || 0;
    const durationStr = durationSec > 0 ? formatDurationHMS(durationSec) : null;

    let paceOrSpeed = "";
    let paceLabel = "";
    if (sportType === "run" && distKm && durationSec > 0) {
      const paceSecKm = item.paceSecPerKm || (durationSec / distKm);
      const pm = Math.floor(paceSecKm / 60);
      const ps = Math.round(paceSecKm % 60);
      paceOrSpeed = `${pm}:${String(ps).padStart(2, "0")}`;
      paceLabel = "min/km";
    } else if (sportType === "bike" && distKm && durationSec > 0) {
      paceOrSpeed = ((distKm / durationSec) * 3600).toFixed(1);
      paceLabel = "km/h";
    }

    const avgHr = item.avgHeartrate || item.average_heartrate || null;
    const elevGain = (item.elevationGainM || item.total_elevation_gain) ? Math.round(item.elevationGainM || item.total_elevation_gain) : null;
    const avgWatts = item.avgWatts || item.average_watts || null;
    const calories = item.calories ? Math.round(item.calories) : null;

    const title = item.title || item.name || `${sportLabel} am ${dateValid ? date.toLocaleDateString("de-DE", { day: "numeric", month: "short" }) : "?"}`;

    let statsHtml = "";
    if (distKm) statsHtml += `<div class="act-stat"><span class="act-stat-val">${distKm.toFixed(1)}</span><span class="act-stat-label">km</span></div>`;
    if (durationStr) statsHtml += `<div class="act-stat"><span class="act-stat-val">${durationStr}</span><span class="act-stat-label">Zeit</span></div>`;
    if (paceOrSpeed) statsHtml += `<div class="act-stat"><span class="act-stat-val">${paceOrSpeed}</span><span class="act-stat-label">${escapeHtml(paceLabel)}</span></div>`;
    if (avgHr) statsHtml += `<div class="act-stat"><span class="act-stat-val">${Math.round(avgHr)}</span><span class="act-stat-label">bpm</span></div>`;
    if (elevGain) statsHtml += `<div class="act-stat"><span class="act-stat-val">${Math.round(elevGain)}</span><span class="act-stat-label">Hm</span></div>`;
    if (avgWatts) statsHtml += `<div class="act-stat"><span class="act-stat-val">${Math.round(avgWatts)}</span><span class="act-stat-label">W</span></div>`;
    if (calories) statsHtml += `<div class="act-stat"><span class="act-stat-val">${Math.round(calories)}</span><span class="act-stat-label">kcal</span></div>`;

    return `
      <article class="activity-card" data-activity-id="${escapeHtml(item.id)}" data-activity-owner="${escapeHtml(account?.email || '')}">
        <div class="activity-card-head">
          <div class="activity-card-avatar ${actorAvatar ? "has-image" : ""}" style="${actorAvatar ? `background-image:url('${actorAvatar}')` : ""}">${escapeHtml(initials)}</div>
          <div class="activity-card-meta">
            <span class="activity-card-name">${escapeHtml(displayName)}</span>
            <span class="activity-card-date">${escapeHtml(dateStr)} · ${escapeHtml(timeStr)}</span>
          </div>
          <span class="activity-card-type" data-sport="${escapeHtml(sportType)}">${getActivitySportIcon(sportType)}<span>${escapeHtml(sportLabel)}</span></span>
        </div>
        <h3 class="activity-card-title">${escapeHtml(title)}</h3>
        ${statsHtml ? `<div class="activity-card-stats">${statsHtml}</div>` : ""}
        ${item.polyline && _idx < 5 ? `<div class="activity-card-map">${renderRouteMapSvg(item, { width: 640, height: 160 })}</div>` : ""}
      </article>
    `;
  }).join("");

  // Event delegation — single listener, not per-card
  if (!container._delegated) {
    container._delegated = true;
    container.addEventListener("click", (e) => {
      const card = e.target.closest(".activity-card[data-activity-id]");
      if (!card) return;
      const activityId = card.dataset.activityId;
      const ownerEmail = card.dataset.activityOwner;
      if (activityId) openActivityDetail(ownerEmail, activityId);
    });
  }
}

function formatRelativeDate(date) {
  const now = new Date();
  const diffMs = now - date;
  const diffDays = Math.floor(diffMs / 86400000);
  if (diffDays === 0 && date.toDateString() === now.toDateString()) return "Heute";
  if (diffDays <= 1 && date.toDateString() !== now.toDateString()) return "Gestern";
  if (diffDays < 7) return `vor ${diffDays} Tagen`;
  return date.toLocaleDateString("de-DE", { day: "numeric", month: "long", year: "numeric" });
}

function formatActivityFeedDate(iso) {
  if (!iso) return "";
  const d = new Date(iso);
  const now = new Date();
  const diffMs = now.getTime() - d.getTime();
  const diffDays = Math.floor(diffMs / 86400000);
  const timeStr = d.toLocaleTimeString("de-DE", { hour: "2-digit", minute: "2-digit" });

  if (diffDays === 0) {
    // Check if actually today
    if (d.toDateString() === now.toDateString()) return `Heute, ${timeStr}`;
    return `Gestern, ${timeStr}`;
  }
  if (diffDays === 1 || (diffDays === 0 && d.toDateString() !== now.toDateString())) return `Gestern, ${timeStr}`;
  if (diffDays < 7) return `vor ${diffDays} Tagen`;
  return d.toLocaleDateString("de-DE", { day: "numeric", month: "short", year: d.getFullYear() !== now.getFullYear() ? "numeric" : undefined });
}

function formatDurationHMS(totalSec) {
  const h = Math.floor(totalSec / 3600);
  const m = Math.floor((totalSec % 3600) / 60);
  const s = Math.round(totalSec % 60);
  if (h > 0) return `${h}:${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")}`;
  return `${m}:${String(s).padStart(2, "0")}`;
}

function normalizeSportType(type, sport) {
  const raw = String(type || sport || "").toLowerCase();
  if (raw.includes("run") || raw.includes("lauf") || raw === "jog") return "run";
  if (raw.includes("trail")) return "trail";
  if (raw.includes("ride") || raw.includes("bike") || raw.includes("cycling") || raw === "radfahren" || raw.includes("radfahr")) return "bike";
  if (raw.includes("mountainbike") || raw === "mtb") return "mtb";
  if (raw.includes("swim") || raw === "schwimmen") return "swim";
  if (raw.includes("hyrox")) return "hyrox";
  if (raw.includes("yoga")) return "yoga";
  if (raw.includes("pilates")) return "pilates";
  if (raw.includes("weighttraining") || raw.includes("strength") || raw.includes("kraft") || raw === "gym") return "gym";
  if (raw.includes("crossfit") || raw.includes("hiit") || raw === "wod") return "crossfit";
  if (raw.includes("row")) return "row";
  if (raw.includes("walk") || raw.includes("gehen") || raw.includes("spazier")) return "walk";
  if (raw.includes("hike") || raw.includes("wander")) return "hike";
  if (raw.includes("ski") || raw.includes("snowboard")) return "ski";
  if (raw.includes("climb") || raw.includes("kletter")) return "climb";
  if (raw.includes("elliptical") || raw.includes("crosstrain")) return "elliptical";
  if (raw.includes("skate") || raw.includes("inline")) return "skate";
  if (raw.includes("triath")) return "triathlon";
  return "other";
}

function formatActivityFeedSportLabel(sportType) {
  const map = {
    run: "Laufen", trail: "Trailrunning", bike: "Radfahren", mtb: "MTB", swim: "Schwimmen",
    hyrox: "HYROX", yoga: "Yoga", pilates: "Pilates", gym: "Krafttraining",
    crossfit: "CrossFit", row: "Rudern", walk: "Gehen", hike: "Wandern",
    ski: "Ski/Snowboard", climb: "Klettern", elliptical: "Crosstrainer",
    skate: "Skating", triathlon: "Triathlon", other: "Workout",
  };
  return map[sportType] || "Workout";
}

