/* ═══════════════════════════════════════════════════════════════════════════
   VDOT PACE CALCULATOR & TRAINING ZONE SYSTEM
   Based on Jack Daniels' Running Formula & modern training science.
   Provides: VDOT estimation, 5 training pace zones, HR zones, power zones,
   nutrition guidance, and polarized distribution tracking.
   ═══════════════════════════════════════════════════════════════════════════ */

// VDOT reference table: [vdot, 5kSec, 10kSec, halfSec, marathonSec, easyMinPace, easyMaxPace, marathonPace, thresholdPace, intervalPace, repPace]
// Paces in seconds per km
const VDOT_TABLE = [
  [20, 2220, 4620, 10440, 22200, 590, 540, 508, 468, 428, 396],
  [22, 2040, 4230, 9540, 20100, 555, 510, 475, 438, 400, 370],
  [24, 1890, 3924, 8820, 18540, 525, 482, 448, 414, 377, 349],
  [26, 1770, 3672, 8244, 17340, 500, 460, 426, 394, 358, 332],
  [28, 1680, 3492, 7836, 16500, 484, 444, 412, 380, 345, 319],
  [30, 1620, 3360, 7500, 15720, 471, 432, 400, 368, 333, 308],
  [32, 1512, 3138, 7020, 14760, 442, 406, 375, 346, 313, 290],
  [34, 1416, 2940, 6576, 13860, 416, 382, 353, 326, 296, 274],
  [36, 1332, 2766, 6180, 13020, 393, 361, 333, 308, 280, 259],
  [38, 1254, 2604, 5820, 12240, 372, 342, 316, 292, 266, 246],
  [40, 1182, 2460, 5490, 11520, 353, 325, 300, 277, 253, 234],
  [42, 1116, 2322, 5190, 10860, 336, 309, 286, 264, 241, 223],
  [44, 1056, 2196, 4920, 10260, 320, 294, 273, 252, 230, 213],
  [46, 1002, 2082, 4668, 9720, 306, 281, 261, 241, 220, 204],
  [48, 948, 1974, 4440, 9240, 292, 269, 250, 231, 211, 196],
  [50, 900, 1872, 4230, 8760, 280, 258, 240, 222, 203, 188],
  [52, 858, 1782, 4032, 8340, 269, 248, 231, 213, 195, 181],
  [54, 816, 1698, 3852, 7980, 258, 238, 222, 205, 188, 174],
  [56, 780, 1620, 3684, 7620, 248, 229, 214, 198, 181, 168],
  [58, 744, 1548, 3528, 7320, 239, 221, 206, 191, 175, 162],
  [60, 714, 1482, 3384, 7020, 231, 213, 199, 185, 169, 157],
  [62, 684, 1422, 3252, 6780, 223, 206, 193, 179, 164, 152],
  [64, 654, 1362, 3126, 6540, 215, 199, 187, 173, 159, 147],
  [66, 630, 1308, 3012, 6336, 208, 193, 181, 168, 154, 143],
  [68, 606, 1260, 2904, 6120, 202, 187, 176, 163, 150, 139],
  [70, 582, 1212, 2808, 5940, 196, 182, 171, 159, 146, 135],
  [72, 564, 1170, 2712, 5760, 190, 177, 166, 154, 142, 132],
  [75, 534, 1110, 2580, 5460, 182, 169, 159, 148, 136, 126],
  [80, 492, 1020, 2400, 5100, 169, 158, 148, 138, 127, 118],
  [85, 456, 948,  2232, 4800, 158, 148, 139, 130, 120, 111],
];

function vdotFromRaceTime(distanceKm, timeSec) {
  if (!Number.isFinite(distanceKm) || !Number.isFinite(timeSec) || timeSec <= 0 || distanceKm <= 0) return null;
  const colMap = { 5: 1, 10: 2, 21.1: 3, 42.2: 4 };
  let col = colMap[distanceKm];
  if (!col) {
    // Find closest standard distance
    const dists = [5, 10, 21.1, 42.2];
    const closest = dists.reduce((a, b) => Math.abs(b - distanceKm) < Math.abs(a - distanceKm) ? b : a);
    col = colMap[closest];
    // Adjust time proportionally
    timeSec = timeSec * (closest / distanceKm);
  }
  // Interpolate VDOT from table
  for (let i = 0; i < VDOT_TABLE.length - 1; i++) {
    const lo = VDOT_TABLE[i];
    const hi = VDOT_TABLE[i + 1];
    if (timeSec <= lo[col] && timeSec >= hi[col]) {
      const frac = (lo[col] - timeSec) / Math.max(1, lo[col] - hi[col]);
      return lo[0] + frac * (hi[0] - lo[0]);
    }
  }
  // Extrapolate if outside table
  if (timeSec > VDOT_TABLE[0][col]) return Math.max(25, VDOT_TABLE[0][0] - (timeSec - VDOT_TABLE[0][col]) / 60);
  if (timeSec < VDOT_TABLE[VDOT_TABLE.length - 1][col]) return Math.min(90, VDOT_TABLE[VDOT_TABLE.length - 1][0] + (VDOT_TABLE[VDOT_TABLE.length - 1][col] - timeSec) / 30);
  return 40; // safe fallback
}

function vdotFromProfile(profile) {
  // Try to derive VDOT from PBs, goal time, or threshold pace
  const pbs = [
    { dist: profile?.pb1Distance, time: profile?.pb1Time },
    { dist: profile?.pb2Distance, time: profile?.pb2Time },
  ].filter(pb => pb.dist && pb.time);

  const vdots = [];
  for (const pb of pbs) {
    const km = distanceKmFromGoal(pb.dist);
    const sec = parseGoalTimeToSeconds(pb.time);
    if (km && sec) {
      const v = vdotFromRaceTime(km, sec);
      if (v) vdots.push(v);
    }
  }

  // Try goal time
  if (profile?.goalTime && profile?.goalDistance && (profile?.discipline === "running")) {
    const km = distanceKmFromGoal(profile.goalDistance);
    const sec = parseGoalTimeToSeconds(profile.goalTime);
    if (km && sec) {
      const v = vdotFromRaceTime(km, sec);
      if (v) vdots.push(v * 0.97); // goal is aspirational, slightly discount
    }
  }

  // Try threshold pace
  const thrPaceSec = profile?.runThresholdPace
    ? (typeof profile.runThresholdPace === "number" ? profile.runThresholdPace : parsePacePerKmToSeconds(String(profile.runThresholdPace)))
    : null;
  if (thrPaceSec) {
    // Threshold pace ≈ VDOT threshold column
    for (let i = 0; i < VDOT_TABLE.length - 1; i++) {
      const lo = VDOT_TABLE[i];
      const hi = VDOT_TABLE[i + 1];
      if (thrPaceSec <= lo[8] && thrPaceSec >= hi[8]) {
        const frac = (lo[8] - thrPaceSec) / Math.max(1, lo[8] - hi[8]);
        vdots.push(lo[0] + frac * (hi[0] - lo[0]));
        break;
      }
    }
  }

  if (vdots.length) return vdots.reduce((a, b) => a + b, 0) / vdots.length;

  // Fallback by level
  return { starter: 33, intermediate: 42, advanced: 55 }[profile?.fitnessLevel] || 38;
}

/*
 * VO2max estimation from VDOT using Daniels' oxygen cost formulas
 * Source: Jack Daniels, "Daniels' Running Formula", 3rd ed.
 *
 * VO2 demand at velocity v (m/min):
 *   VO2 = -4.60 + 0.182258·v + 0.000104·v²
 *
 * Fraction of VO2max sustainable at duration t (min):
 *   F = 0.8 + 0.1894393·e^(-0.012778·t) + 0.2989558·e^(-0.1932605·t)
 *
 * VO2max = VO2_demand / F_fraction
 *
 * We use the best available race data; if none, derive from VDOT table pace.
 */
/**
 * Daniels VO2 demand at velocity v (m/min)
 */
function daniels_vo2demand(velocityMperMin) {
  return -4.60 + 0.182258 * velocityMperMin + 0.000104 * velocityMperMin * velocityMperMin;
}

/**
 * Daniels sustainable fraction of VO2max at duration t (min)
 */
function daniels_fraction(durationMin) {
  return 0.8 + 0.1894393 * Math.exp(-0.012778 * durationMin) + 0.2989558 * Math.exp(-0.1932605 * durationMin);
}

/**
 * VO2max estimation — hybrid race + HR-based (Firstbeat-style) approach.
 *
 * Garmin / Strava use HR-pace regression during submaximal runs (Firstbeat
 * method). Pure race-based VDOT estimates run 2-4 ml/kg/min higher because
 * they assume the runner maxes out effort.
 *
 * Hybrid strategy:
 *   1. If recent run with HR data exists → HR-adjusted median (matches Garmin)
 *   2. If race PB within 90 days → blend race-VDOT + HR estimate
 *   3. Else → VDOT table lookup from profile PBs
 *   4. Fallback → level-based default
 */
function estimateVO2max(profile, activities) {
  // Auto-pull activities from current account if not supplied
  if (!activities) {
    try {
      const acc = typeof getCurrentAccount === "function" ? getCurrentAccount() : null;
      activities = acc?.activities ? (typeof normalizeActivities === "function" ? normalizeActivities(acc.activities) : acc.activities) : [];
    } catch (_) { activities = []; }
  }
  activities = activities || [];
  const maxHr = Number(profile?.maxHr) || null;
  const restingHr = Number(profile?.restingHr) || 60;
  const age = profile?.birthYear ? (new Date().getFullYear() - profile.birthYear) : null;
  // Age-based maxHR fallback (Tanaka 2001: 208 - 0.7·age, more accurate than 220-age)
  const estMaxHr = maxHr || (age ? Math.round(208 - 0.7 * age) : 190);
  const hrReserve = Math.max(50, estMaxHr - restingHr);

  // --- HR-based estimation (corrected HRR model) ---
  // Relationship (Swain & Leutholtz 1997): %HRR ≈ %VO2R
  // where VO2R = VO2max - VO2rest (VO2rest ≈ 3.5 ml/kg/min)
  // So: VO2max = (VO2session - 3.5) / %HRR + 3.5
  //
  // Requires *hard* runs (≥70% HRR) to produce stable estimates; easy
  // Z1/Z2 runs at sub-maximal HR yield too much extrapolation noise.
  const VO2_REST = 3.5;
  const now = Date.now();
  const ms90 = 90 * 86400000;
  const recentRunsWithHr = activities
    .filter(a => a.sportType === "run"
      && Number(a.distanceKm) > 2.0
      && Number(a.movingTimeSec) > 900 // ≥15 min, excludes warmups/easy jogs
      && Number(a.avgHeartrate) > 100
      && (now - new Date(a.createdAt || 0).getTime()) < ms90)
    .map(a => {
      const paceMperMin = (Number(a.distanceKm) * 1000) / (Number(a.movingTimeSec) / 60);
      const vo2demand = daniels_vo2demand(paceMperMin);
      const hrr = Math.max(0.20, Math.min(0.98, (Number(a.avgHeartrate) - restingHr) / hrReserve));
      // HRR-based back-projection to VO2max
      const vo2max = (vo2demand - VO2_REST) / hrr + VO2_REST;
      return { vo2max, hrr, vo2demand, avgHr: a.avgHeartrate, pace: paceMperMin };
    })
    .filter(r => Number.isFinite(r.vo2max) && r.vo2max > 20 && r.vo2max < 90);

  // Gate: only runs at ≥70% HRR produce reliable back-projection
  const hardRuns = recentRunsWithHr.filter(r => r.hrr >= 0.70).sort((a, b) => a.vo2max - b.vo2max);
  // If we lack hard runs, fall back to moderate runs (≥55% HRR) but down-weight
  const modRuns = hardRuns.length < 3 ? recentRunsWithHr.filter(r => r.hrr >= 0.55).sort((a, b) => a.vo2max - b.vo2max) : [];

  let hrEstimate = null;
  let hrQuality = null;
  if (hardRuns.length >= 3) {
    // 75th percentile of hard runs — reflects true capacity, filters outliers
    const idx = Math.floor(hardRuns.length * 0.75);
    hrEstimate = hardRuns[Math.min(idx, hardRuns.length - 1)].vo2max;
    hrQuality = "hard";
  } else if (modRuns.length >= 5) {
    // Median of moderate runs, minus 2 ml (bias correction for sub-threshold extrapolation)
    const idx = Math.floor(modRuns.length * 0.5);
    hrEstimate = modRuns[Math.min(idx, modRuns.length - 1)].vo2max - 2.0;
    hrQuality = "moderate";
  }

  // --- Race-based VDOT estimation (Daniels) ---
  const pbData = extractPbDataForPrediction ? extractPbDataForPrediction(profile) : [];
  let raceEstimate = null;
  if (pbData.length) {
    const scored = pbData.map(pb => {
      const durationMin = pb.timeSec / 60;
      const optimalDist = Math.abs(durationMin - 12);
      return { ...pb, durationMin, optimalDist };
    }).sort((a, b) => a.optimalDist - b.optimalDist);
    const best = scored[0];
    const velocityMperMin = (best.distKm * 1000) / best.durationMin;
    const vo2demand = daniels_vo2demand(velocityMperMin);
    const fraction = daniels_fraction(best.durationMin);
    const vo2max = vo2demand / fraction;
    // Apply slight deflation (-2 ml) to align with Garmin/Strava (pure race = higher)
    if (Number.isFinite(vo2max) && vo2max > 15 && vo2max < 95) {
      raceEstimate = vo2max - 2.0;
    }
  }

  // --- Blending logic ---
  // HR-based alone: use it (matches Garmin approach most closely)
  // Both available: weighted blend (0.7 HR / 0.3 race) — HR captures current state
  // Race only: use race estimate
  let value, source, confidence;
  if (hrEstimate != null && raceEstimate != null) {
    // Race is the ground truth; HR gives current-state adjustment. Weight race higher.
    const hrWeight = hrQuality === "hard" ? 0.45 : 0.30;
    value = raceEstimate * (1 - hrWeight) + hrEstimate * hrWeight;
    source = "hr+race";
    confidence = hrQuality === "hard" ? "high" : "moderate";
  } else if (hrEstimate != null) {
    value = hrEstimate;
    source = hrQuality === "hard" ? "hr" : "hr-mod";
    confidence = hrQuality === "hard" && hardRuns.length >= 8 ? "high" : "moderate";
  } else if (raceEstimate != null) {
    value = raceEstimate;
    source = "race";
    confidence = "moderate";
  } else {
    // VDOT fallback
    const vdot = vdotFromProfile(profile);
    if (vdot) {
      const preds = vdotRacePredictions(vdot);
      const fiveKTimeSec = preds.fiveK;
      if (fiveKTimeSec > 0) {
        const durationMin = fiveKTimeSec / 60;
        const velocityMperMin = 5000 / durationMin;
        const vo2demand = daniels_vo2demand(velocityMperMin);
        const fraction = daniels_fraction(durationMin);
        const vo2max = vo2demand / fraction - 2.0;
        if (Number.isFinite(vo2max) && vo2max > 15 && vo2max < 95) {
          return { value: +vo2max.toFixed(1), source: "vdot", confidence: "low" };
        }
      }
    }
    const fallback = { starter: 32, intermediate: 42, advanced: 55 }[profile?.fitnessLevel] || 38;
    return { value: fallback, source: "estimate", confidence: "low" };
  }

  // Age-plausibility clamp: 1.55× = true elite (sub-3h marathon),
  // 1.40× = strong amateur / sub-elite. We cap at 1.40× for typical users
  // and only allow up to 1.55× if the estimate came from a clean race PB.
  if (age) {
    const sex = profile?.sex === "female" ? "f" : "m";
    const popMean = sex === "m" ? (57 - 0.40 * age) : (48 - 0.37 * age);
    const ceiling = source === "race" ? popMean * 1.55 : popMean * 1.40;
    if (value > ceiling) value = ceiling;
    // also a hard floor: 50% of popMean (really untrained)
    const floor = popMean * 0.55;
    if (value < floor) value = floor;
  }

  return { value: +value.toFixed(1), source, confidence };
}

/*
 * Fitness Age — biological age based on VO2max percentile
 * Source: HUNT study (Nes et al., 2013) & ACSM normative data
 *
 * VO2max declines ~1% per year after age 25 in untrained individuals
 * A 50-year-old with VO2max of 48 has the fitness of an average 30-year-old
 *
 * Reference tables (ml/kg/min, median by age/sex):
 *   Male:   20s→47, 30s→44, 40s→41, 50s→37, 60s→33, 70s→29
 *   Female: 20s→40, 30s→37, 40s→34, 50s→31, 60s→28, 70s→25
 */
/**
 * Multi-factor Fitness Age breakdown (WHOOP-inspired, transparent).
 * Returns signed year-deltas per component + weighted composite.
 * Research: Nes 2011/2013 (HUNT), Kodama 2009 (JAMA), Lifelines HRV norms, WHOOP Healthspan 2024.
 * See FORMULAS.md §7 for full formula derivation + sources.
 */
function computeFitnessAgeBreakdown(account) {
  const profile = account?.profile || {};
  const chronoAge = profile.birthYear ? (new Date().getFullYear() - profile.birthYear) : null;
  if (!chronoAge) return null;
  const sex = profile.sex || "male";
  const clamp = (v, lo, hi) => Math.max(lo, Math.min(hi, v));
  const activities = account?.activities || [];
  const now = Date.now();
  const ms = 86400000;
  const recent90 = activities.filter(a => {
    const d = new Date(a.createdAt || a.date || a.start_date || 0).getTime();
    return d > now - 90 * ms;
  });

  const components = [];

  // Weights aligned with WHOOP Healthspan 2024 + Kodama 2009 (JAMA):
  //   VO2max is strongest single predictor (13%/MET mortality reduction),
  //   but WHOOP balances across 9 inputs. HRV explicitly NOT used by WHOOP for age
  //   (too genetically individualized) → demoted to 0.05.
  // A) VO2max delta (Garmin/HUNT convention: -0.2 per ml/kg/min above pop mean)
  const vo2Result = typeof estimateVO2max === "function" ? estimateVO2max(profile) : null;
  const vo2 = vo2Result?.value ?? null;
  if (vo2) {
    const popMean = sex === "female" ? (48 - 0.37 * chronoAge) : (57 - 0.40 * chronoAge);
    // Calibrated to WHOOP: less aggressive than Garmin (which uses -0.2 and can
    // show -9 to -11 yr). 0.15 keeps top delta around ±6 yr.
    const deltaYr = clamp(-0.15 * (vo2 - popMean), -6, 6);
    components.push({
      key: "vo2max", label: "VO2max",
      inputText: `${vo2.toFixed(1)} ml/kg/min (Norm ${popMean.toFixed(0)})`,
      deltaYr, weight: 0.35, available: true,
    });
  } else {
    components.push({ key: "vo2max", label: "VO2max", inputText: "keine Daten", deltaYr: 0, weight: 0.35, available: false });
  }

  // B) Activity delta: steps-proxy (sessions+minutes) & zone-2 time
  let actDelta = 0;
  if (recent90.length) {
    const weeklyMin = recent90.reduce((s, a) => s + ((a.movingTimeSec || a.moving_time || 0) / 60), 0) / 13;
    const weeklyCount = recent90.length / 13;
    // Map to daily-steps-equivalent: rough proxy, 1 active session ~ 3000 step equiv.
    const stepsEquiv = 4000 + weeklyCount * 600 + weeklyMin * 15;
    actDelta = clamp(-0.0015 * (stepsEquiv - 6000), -3, 3);
    components.push({
      key: "activity", label: "Aktivität",
      inputText: `${weeklyCount.toFixed(1)}×/Wo · ${Math.round(weeklyMin)} min/Wo`,
      deltaYr: actDelta, weight: 0.25, available: true,
    });
  } else {
    components.push({ key: "activity", label: "Aktivität", inputText: "keine Daten", deltaYr: 0, weight: 0.25, available: false });
  }

  // C) Sleep delta (optional)
  const sleepHours = profile.avgSleepHours || account?.healthData?.avgSleepHours;
  if (sleepHours) {
    const deviation = Math.abs(sleepHours - 7.5);
    const sleepDelta = clamp(deviation * 2 - 1.5, -3, 5);
    components.push({
      key: "sleep", label: "Schlaf",
      inputText: `${sleepHours.toFixed(1)} h/Nacht`,
      deltaYr: sleepDelta, weight: 0.20, available: true,
    });
  } else {
    components.push({ key: "sleep", label: "Schlaf", inputText: "keine Daten", deltaYr: 0, weight: 0.20, available: false });
  }

  // D) RHR delta
  const rhr = profile.restingHr || account?.healthData?.restingHr;
  if (rhr) {
    const popRhr = 65 + 0.03 * chronoAge;
    const rhrDelta = clamp(0.15 * (rhr - popRhr), -3, 4);
    components.push({
      key: "rhr", label: "Ruhepuls",
      inputText: `${rhr} bpm (Norm ${popRhr.toFixed(0)})`,
      deltaYr: rhrDelta, weight: 0.10, available: true,
    });
  } else {
    components.push({ key: "rhr", label: "Ruhepuls", inputText: "keine Daten", deltaYr: 0, weight: 0.10, available: false });
  }

  // E) HRV delta (RMSSD, log-linear norm from Lifelines/Nunan)
  const rmssd = profile.hrvRmssd || account?.healthData?.rmssd;
  if (rmssd && rmssd > 0) {
    const expectedLn = 4.3 - 0.022 * chronoAge;
    const hrvDelta = clamp(-10 * (Math.log(rmssd) - expectedLn), -3, 3);
    components.push({
      key: "hrv", label: "HRV (RMSSD)",
      inputText: `${Math.round(rmssd)} ms`,
      deltaYr: hrvDelta, weight: 0.05, available: true,
    });
  } else {
    components.push({ key: "hrv", label: "HRV (RMSSD)", inputText: "keine Daten", deltaYr: 0, weight: 0.05, available: false });
  }

  // F) Body composition delta (WHR)
  const whr = profile.waistHipRatio;
  if (whr) {
    const target = sex === "female" ? 0.85 : 0.90;
    const whrDelta = clamp(10 * (whr - target), -2, 3);
    components.push({
      key: "body", label: "Körperkomposition",
      inputText: `WHR ${whr.toFixed(2)}`,
      deltaYr: whrDelta, weight: 0.05, available: true,
    });
  } else {
    components.push({ key: "body", label: "Körperkomposition", inputText: "keine Daten", deltaYr: 0, weight: 0.05, available: false });
  }

  // Renormalize weights over available components
  const totalAvailWeight = components.filter(c => c.available).reduce((s, c) => s + c.weight, 0) || 1;
  components.forEach(c => { c.effectiveWeight = c.available ? (c.weight / totalAvailWeight) : 0; });
  components.forEach(c => { c.contributionYr = c.deltaYr * c.effectiveWeight; });

  const netDelta = components.reduce((s, c) => s + c.contributionYr, 0);
  const fitnessAge = clamp(chronoAge + netDelta, chronoAge - 10, chronoAge + 10);
  const missingTierA = components.filter(c => !c.available && ["vo2max"].includes(c.key)).length;
  const confidence = clamp(2 + 3 * missingTierA + components.filter(c => !c.available).length * 0.5, 2, 8);

  return { chronoAge, fitnessAge: Math.round(fitnessAge), netDelta, components, confidence };
}

/**
 * Render the fitness-age component breakdown card for transparency.
 */
function renderFitnessAgeBreakdown(account) {
  const el = document.getElementById("fitness-age-breakdown");
  if (!el) return;
  const bd = computeFitnessAgeBreakdown(account);
  if (!bd) { el.hidden = true; return; }
  el.hidden = false;

  const fmtYr = (v) => (v >= 0 ? "+" : "") + v.toFixed(1);
  const tone = (v) => v <= -0.3 ? "pos" : v >= 1.5 ? "neg-strong" : v >= 0.3 ? "neg" : "neu";

  const available = bd.components.filter(c => c.available);
  const sorted = available.slice().sort((a, b) => a.contributionYr - b.contributionYr);
  const topPositive = sorted[0] && sorted[0].contributionYr < 0 ? sorted[0] : null;
  const topNegative = sorted[sorted.length - 1] && sorted[sorted.length - 1].contributionYr > 0 ? sorted[sorted.length - 1] : null;

  const pillPos = topPositive
    ? `<span class="fa-pill fa-pill-pos"><span class="fa-pill-icon">↓</span>${topPositive.label} <b>${fmtYr(topPositive.contributionYr)} J</b></span>`
    : "";
  const pillNeg = topNegative
    ? `<span class="fa-pill fa-pill-neg"><span class="fa-pill-icon">↑</span>${topNegative.label} <b>${fmtYr(topNegative.contributionYr)} J</b></span>`
    : "";

  const allRows = available
    .slice()
    .sort((a, b) => Math.abs(b.contributionYr) - Math.abs(a.contributionYr))
    .map(c => `<li class="fa-bd-row">
        <span class="fa-bd-label">${c.label}</span>
        <span class="fa-bd-bar"><span class="fa-bd-bar-fill tone-${tone(c.contributionYr)}" style="width:${Math.min(100, Math.abs(c.contributionYr) * 30)}%"></span></span>
        <span class="fa-bd-contrib tone-${tone(c.contributionYr)}">${fmtYr(c.contributionYr)}</span>
      </li>`).join("");

  const missing = bd.components.filter(c => !c.available).map(c => c.label);
  const missingHint = missing.length ? `<div class="fa-bd-missing-hint">Noch ohne Daten: ${missing.join(" · ")}</div>` : "";

  el.innerHTML = `
    <div class="fa-pills">${pillPos}${pillNeg}</div>
    <details class="fa-bd-details">
      <summary class="fa-bd-summary">Alle Faktoren anzeigen</summary>
      <ul class="fa-bd-list">${allRows}</ul>
      ${missingHint}
    </details>
  `;
}

function estimateFitnessAge(vo2max, sex, chronologicalAge) {
  // Whoop-inspired multi-factor Fitness Age:
  // VO2max accounts for ~50% of score, activity scoring ~30%, resting HR ~20%
  // Primary VO2max mapping: Nes et al. 2013 (HUNT3, n=3,320) linear regression
  //   Male:   expected VO2max = 57.8 − 0.31 × age
  //   Female: expected VO2max = 46.3 − 0.25 × age
  if (!chronologicalAge || chronologicalAge <= 0) return null;
  const account = getCurrentAccount();
  const activities = account?.activities || [];

  // 1) VO2max component (0-50 points, lower = younger)
  let vo2Score = 0;
  if (vo2max && vo2max > 0) {
    // ACSM percentile tables — high VO2max = big age reduction
    const maleRef = [[20,51],[25,49],[30,47],[35,45],[40,43],[45,41],[50,39],[55,37],[60,35],[65,32],[70,30],[75,28],[80,25]];
    const femaleRef = [[20,44],[25,42],[30,40],[35,38],[40,36],[45,34],[50,32],[55,30],[60,28],[65,26],[70,24],[75,22],[80,20]];
    const ref = sex === "female" ? femaleRef : maleRef;
    // Find VO2max-based age
    let vo2Age = chronologicalAge;
    if (vo2max >= ref[0][1]) {
      vo2Age = Math.max(18, ref[0][0] - Math.round((vo2max - ref[0][1]) * 0.8));
    } else if (vo2max <= ref[ref.length - 1][1]) {
      vo2Age = ref[ref.length - 1][0];
    } else {
      for (let i = 0; i < ref.length - 1; i++) {
        if (vo2max <= ref[i][1] && vo2max >= ref[i + 1][1]) {
          const frac = (ref[i][1] - vo2max) / Math.max(1, ref[i][1] - ref[i + 1][1]);
          vo2Age = Math.round(ref[i][0] + frac * (ref[i + 1][0] - ref[i][0]));
          break;
        }
      }
    }
    vo2Score = vo2Age - chronologicalAge; // negative = younger, positive = older
  }

  // 2) Activity scoring (invisible points, 0–30 adjustment)
  const now = Date.now();
  const msPerDay = 86400000;
  const recent90 = activities.filter(a => {
    const d = new Date(a.createdAt || 0).getTime();
    return d > now - 90 * msPerDay;
  });
  // Score: frequency, duration variety, intensity
  const weeklyCount = recent90.length / 13; // avg sessions per week over 90d
  const totalMinutes = recent90.reduce((s, a) => s + ((a.movingTimeSec || 0) / 60), 0);
  const weeklyMinutes = totalMinutes / 13;
  const sportTypes = new Set(recent90.map(a => a.sportType)).size;

  // Activity age adjustment: active people get younger
  let activityAdj = 0;
  // Frequency bonus: 3-5x/week is optimal (WHO guidelines: 150-300 min moderate)
  if (weeklyCount >= 5) activityAdj -= 4;
  else if (weeklyCount >= 3) activityAdj -= 3;
  else if (weeklyCount >= 2) activityAdj -= 1.5;
  else if (weeklyCount >= 1) activityAdj -= 0.5;
  else activityAdj += 2; // sedentary penalty

  // Volume bonus: 150+ min/week
  if (weeklyMinutes >= 300) activityAdj -= 3;
  else if (weeklyMinutes >= 150) activityAdj -= 2;
  else if (weeklyMinutes >= 75) activityAdj -= 1;

  // Variety bonus: cross-training
  if (sportTypes >= 3) activityAdj -= 1.5;
  else if (sportTypes >= 2) activityAdj -= 0.5;

  // Intensity bonus: high-intensity sessions (HR > 160 or pace-based)
  const highIntensity = recent90.filter(a => (a.avgHeartrate && a.avgHeartrate > 155) || (a.maxHeartrate && a.maxHeartrate > 175)).length;
  const hiPerWeek = highIntensity / 13;
  if (hiPerWeek >= 2) activityAdj -= 1.5;
  else if (hiPerWeek >= 1) activityAdj -= 0.5;

  // Long sessions bonus (endurance)
  const longSessions = recent90.filter(a => (a.movingTimeSec || 0) > 3600).length;
  if (longSessions >= 8) activityAdj -= 1;

  // 3) Resting HR component (if available from profile)
  let hrAdj = 0;
  const restingHr = account?.profile?.restingHr || account?.healthData?.restingHr;
  if (restingHr) {
    if (restingHr < 50) hrAdj = -3;
    else if (restingHr < 55) hrAdj = -2;
    else if (restingHr < 60) hrAdj = -1;
    else if (restingHr > 75) hrAdj = 2;
    else if (restingHr > 80) hrAdj = 4;
  }

  // Combine: weighted sum
  const totalAdj = (vo2Score * 0.5) + (activityAdj * 0.3) + (hrAdj * 0.2);
  const fitnessAge = Math.round(chronologicalAge + totalAdj);

  // Clamp to reasonable range
  return Math.max(18, Math.min(chronologicalAge + 15, fitnessAge));
}

/* ═══════════════════════════════════════════════════════════════════════════
   DASHBOARD RINGS — Calculation + Rendering
   ═══════════════════════════════════════════════════════════════════════════ */

function calculateTrainingReadiness(account) {
  // Composite score 0-100 based on 4 factors:
  // ACWR (30%), Consistency (25%), Recovery Time (25%), Freshness (20%)
  const activities = account?.activities || [];
  if (!activities.length) return { score: null, label: "--", components: {} };

  const load = estimateTrainingLoad(activities.filter(a => {
    const d = new Date(a.createdAt || 0).getTime();
    return d > Date.now() - 90 * 86400000;
  }));

  // 1) ACWR component (30%) — sweet spot 0.8-1.3
  let acwrScore = 50;
  if (load?.acwr != null) {
    if (load.acwr >= 0.8 && load.acwr <= 1.3) acwrScore = 80 + (1 - Math.abs(load.acwr - 1.05) / 0.25) * 20;
    else if (load.acwr < 0.8) acwrScore = Math.max(20, load.acwr / 0.8 * 70);
    else acwrScore = Math.max(10, 100 - (load.acwr - 1.3) * 60);
  }

  // 2) Consistency (25%) — regular training pattern
  const now = Date.now();
  const msPerDay = 86400000;
  const last28 = activities.filter(a => new Date(a.createdAt || 0).getTime() > now - 28 * msPerDay);
  const weekBuckets = [0, 0, 0, 0];
  last28.forEach(a => {
    const daysAgo = (now - new Date(a.createdAt || 0).getTime()) / msPerDay;
    const week = Math.min(3, Math.floor(daysAgo / 7));
    weekBuckets[week]++;
  });
  const nonEmptyWeeks = weekBuckets.filter(w => w > 0).length;
  const avgPerWeek = last28.length / 4;
  const consistencyScore = Math.min(100, (nonEmptyWeeks / 4) * 60 + Math.min(avgPerWeek / 4, 1) * 40);

  // 3) Recovery time (25%) — hours since last session
  const sorted = [...activities].sort((a, b) => new Date(b.createdAt || 0) - new Date(a.createdAt || 0));
  const hoursSinceLast = sorted.length ? (now - new Date(sorted[0].createdAt || 0).getTime()) / 3600000 : 999;
  let recoveryScore = 50;
  if (hoursSinceLast >= 24 && hoursSinceLast <= 72) recoveryScore = 90;
  else if (hoursSinceLast >= 12 && hoursSinceLast < 24) recoveryScore = 65;
  else if (hoursSinceLast < 12) recoveryScore = 35;
  else if (hoursSinceLast > 72 && hoursSinceLast <= 120) recoveryScore = 75;
  else recoveryScore = 50; // too long since last session

  // 4) Freshness (20%) — is load trending up or coasting
  let freshnessScore = 50;
  if (load) {
    const freshness = (load.chronicLoad28d || 0) - (load.acuteLoad7d || 0);
    freshnessScore = freshness > 0 ? Math.min(90, 60 + freshness / 10) : Math.max(20, 60 + freshness / 10);
  }

  const score = Math.round(acwrScore * 0.30 + consistencyScore * 0.25 + recoveryScore * 0.25 + freshnessScore * 0.20);
  return {
    score: Math.max(0, Math.min(100, score)),
    label: score >= 80 ? "Peak" : score >= 60 ? "Gut" : score >= 40 ? "Moderat" : "Niedrig",
    components: { acwr: Math.round(acwrScore), consistency: Math.round(consistencyScore), recovery: Math.round(recoveryScore), freshness: Math.round(freshnessScore) }
  };
}

function calculateCurrentStrain(account) {
  // Normalize acute load to 0-100 based on personal chronic load
  const activities = account?.activities || [];
  if (!activities.length) return { score: null };
  const recent = activities.filter(a => new Date(a.createdAt || 0).getTime() > Date.now() - 90 * 86400000);
  const load = estimateTrainingLoad(recent);
  if (!load) return { score: null };

  // Strain = acute load as percentage of expected (chronic) load
  const chronic = load.chronicLoad28d || 1;
  const strain = Math.round((load.acuteLoad7d / chronic) * 50); // normalized so ~50 = baseline
  return { score: Math.max(0, Math.min(100, strain)), acuteLoad: load.acuteLoad7d, chronicLoad: chronic, acwr: load.acwr };
}

function calculateRecoveryScore(account) {
  // Recovery based on time since last session + session intensity
  const activities = account?.activities || [];
  if (!activities.length) return { score: null };
  const sorted = [...activities].sort((a, b) => new Date(b.createdAt || 0) - new Date(a.createdAt || 0));
  const hoursSince = (Date.now() - new Date(sorted[0].createdAt || 0).getTime()) / 3600000;
  const lastIntensity = sorted[0].avgHeartrate ? (sorted[0].avgHeartrate / 150) : 0.8;
  const recoveryHours = 24 + lastIntensity * 12; // harder session = more recovery needed
  const pct = Math.min(1, hoursSince / recoveryHours);
  return { score: Math.round(pct * 100), hoursSince: Math.round(hoursSince) };
}

function getDashboardRingConfig(account) {
  const defaults = { readiness: true, strain: true, recovery: true, hrv: false, sleep: false, steps: false, "fitness-age": false, vo2max: false };
  const raw = account?.settings?.dashboardRings;
  if (!raw) return defaults;
  // Handle positional format: { center: "readiness", left: "strain", right: "recovery" }
  if (raw.center || raw.left || raw.right) {
    const converted = { ...defaults };
    if (raw.center) converted[raw.center] = true;
    if (raw.left) converted[raw.left] = true;
    if (raw.right) converted[raw.right] = true;
    // Preserve the positional hints so renderDashboardRings can use exact positions
    converted._left = raw.left || null;
    converted._right = raw.right || null;
    return converted;
  }
  return raw;
}

/* ── Health Metrics (Resting HR, HRV, Sleep, Recovery) ── */

function renderHealthMetrics(account) {
  if (!account) return;
  const profile = account?.profile || {};
  const acts = account?.activities || [];
  const history = account?.metricHistory || [];

  // Resting HR
  const rhrEl = document.getElementById("health-rhr-value");
  if (rhrEl) {
    const rhr = profile.restingHr || account?.settings?.inputData?.restingHr;
    rhrEl.textContent = rhr || "--";
  }

  // RHR chart
  renderHealthTrendChart("health-rhr-chart", history, "restingHr", {
    color: "#E05252",
    label: "Ruhe-HF",
    unit: "bpm",
    fallbackValue: profile.restingHr
  });

  // HRV
  const hrvEl = document.getElementById("health-hrv-value");
  if (hrvEl) {
    const hrv = history.length > 0 ? history[history.length - 1]?.hrv : null;
    hrvEl.textContent = hrv || "--";
  }

  renderHealthTrendChart("health-hrv-chart", history, "hrv", {
    color: "#8E7CC3",
    label: "HRV",
    unit: "ms",
    fallbackValue: null
  });

  // Sleep
  const sleepEl = document.getElementById("health-sleep-value");
  if (sleepEl) {
    const lastSleep = history.length > 0 ? history[history.length - 1]?.sleepHours : null;
    sleepEl.textContent = lastSleep ? lastSleep.toFixed(1) : "--";
  }

  renderHealthTrendChart("health-sleep-chart", history, "sleepHours", {
    color: "#5B9BD5",
    label: "Schlaf",
    unit: "h",
    fallbackValue: null
  });

  // Recovery
  const recoveryEl = document.getElementById("health-recovery-value");
  if (recoveryEl) {
    const recovery = calculateRecoveryScore(account);
    const score = recovery?.score;
    recoveryEl.textContent = score != null ? Math.round(score) : "--";
    if (score != null) {
      if (score >= 67) recoveryEl.style.color = "#4CAF82";
      else if (score >= 34) recoveryEl.style.color = "#E5A93D";
      else recoveryEl.style.color = "#E05252";
    }
  }

  renderHealthTrendChart("health-recovery-chart", history, "recovery", {
    color: "#4CAF82",
    label: "Recovery",
    unit: "%",
    fallbackValue: null
  });

  // 7-day averages
  const avg7Rhr = document.getElementById("health-rhr-avg7");
  if (avg7Rhr && history.length > 0) {
    const last7 = history.slice(-7).filter(h => h.restingHr).map(h => h.restingHr);
    avg7Rhr.textContent = last7.length > 0 ? Math.round(last7.reduce((a, b) => a + b, 0) / last7.length) + " bpm" : "--";
  }

  const avg7Sleep = document.getElementById("health-sleep-avg7");
  if (avg7Sleep && history.length > 0) {
    const last7 = history.slice(-7).filter(h => h.sleepHours).map(h => h.sleepHours);
    avg7Sleep.textContent = last7.length > 0 ? (last7.reduce((a, b) => a + b, 0) / last7.length).toFixed(1) + " h" : "--";
  }
}

function renderHealthTrendChart(containerId, history, key, opts) {
  const el = document.getElementById(containerId);
  if (!el) return;

  const data = history.filter(h => h[key] != null).slice(-30);

  if (data.length < 2) {
    el.innerHTML = '<div class="health-chart-empty">Daten werden mit der Zeit erfasst</div>';
    return;
  }

  const W = 400, H = 80;
  const vals = data.map(d => d[key]);
  const minV = Math.min(...vals) * 0.95;
  const maxV = Math.max(...vals) * 1.05;
  const range = maxV - minV || 1;

  const points = data.map((d, i) => ({
    x: (i / (data.length - 1)) * (W - 20) + 10,
    y: H - 10 - ((d[key] - minV) / range) * (H - 20)
  }));

  const pathD = points.map((p, i) => `${i === 0 ? "M" : "L"}${p.x},${p.y}`).join(" ");
  const areaD = `M${points[0].x},${H} ${pathD} L${points[points.length - 1].x},${H} Z`;

  el.innerHTML = `
    <svg viewBox="0 0 ${W} ${H}" class="health-trend-svg">
      <defs>
        <linearGradient id="grad-${containerId}" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="${opts.color}" stop-opacity="0.2"/>
          <stop offset="100%" stop-color="${opts.color}" stop-opacity="0"/>
        </linearGradient>
      </defs>
      <path d="${areaD}" fill="url(#grad-${containerId})"/>
      <path d="${pathD}" fill="none" stroke="${opts.color}" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
      <circle cx="${points[points.length - 1].x}" cy="${points[points.length - 1].y}" r="3" fill="${opts.color}"/>
    </svg>
  `;
}

function saveDashboardRingConfig(config) {
  const account = getCurrentAccount();
  if (!account) return;
  if (!account.settings) account.settings = {};
  account.settings.dashboardRings = config;
  persistStore();
}

function renderDashboardRings() {
  const container = document.getElementById("dashboard-rings-container");
  const quickStats = document.getElementById("dashboard-quick-stats");
  if (!container) return;

  const account = getCurrentAccount();
  normalizeActivities(account?.activities);
  const config = getDashboardRingConfig(account);

  // Calculate all metrics
  const readiness = calculateTrainingReadiness(account);
  const strain = calculateCurrentStrain(account);
  const recovery = calculateRecoveryScore(account);

  // Determine which rings to show (max 3: primary center + 2 secondary)
  const activeRings = [];
  const allMetrics = {
    readiness: { score: readiness.score, label: readiness.label },
    strain: { score: strain.score, label: strain.score != null ? strain.score : "--" },
    recovery: { score: recovery.score, label: recovery.score != null ? `${recovery.score}%` : "--" },
    hrv: { score: null, label: "--" },
    sleep: { score: null, label: "--" },
    steps: { score: null, label: "--" },
    "fitness-age": { score: null, label: "--" },
    vo2max: { score: null, label: "--" },
  };

  // Try to populate HRV, sleep etc from health data if available
  if (account?.healthData?.hrv) {
    const hrvVal = account.healthData.hrv;
    allMetrics.hrv = { score: Math.min(100, Math.round(hrvVal / 1.2)), label: `${Math.round(hrvVal)} ms` };
  }
  if (account?.healthData?.sleepScore) {
    allMetrics.sleep = { score: account.healthData.sleepScore, label: `${account.healthData.sleepScore}%` };
  }
  if (account?.healthData?.steps) {
    const stepPct = Math.min(100, Math.round(account.healthData.steps / 100));
    allMetrics.steps = { score: stepPct, label: account.healthData.steps.toLocaleString() };
  }

  // Readiness is always primary (center)
  // Pick 2 secondary from config — use positional hints if available
  const leftType = config._left || Object.keys(config).filter(k => !k.startsWith("_") && k !== "readiness" && config[k])[0] || "strain";
  const rightType = config._right || Object.keys(config).filter(k => !k.startsWith("_") && k !== "readiness" && k !== leftType && config[k])[0] || "recovery";

  // Build ring HTML
  const CIRC = 2 * Math.PI * 88; // ≈ 553

  function buildRing(type, isPrimary) {
    const metric = allMetrics[type] || { score: null, label: "--" };
    const pct = metric.score != null ? metric.score / 100 : 0;
    const offset = CIRC * (1 - pct);
    const cls = isPrimary ? "dashboard-ring-primary" : "dashboard-ring-secondary";
    const displayVal = metric.score != null ? (type === "readiness" ? metric.score : metric.label) : "--";
    return `<div class="dashboard-ring ${cls}" data-ring-type="${type}">
      <svg class="ring-svg" viewBox="0 0 200 200">
        <circle class="ring-track" cx="100" cy="100" r="88" />
        <circle class="ring-progress" cx="100" cy="100" r="88" style="stroke-dashoffset:${offset}" />
      </svg>
      <div class="ring-label">
        <strong class="ring-value">${displayVal}</strong>
        <span class="ring-caption">${t("dashboard_" + type) || type}</span>
      </div>
    </div>`;
  }

  container.innerHTML = buildRing(leftType, false) + buildRing("readiness", true) + buildRing(rightType, false);

  // Quick stats
  if (quickStats) {
    const load = estimateTrainingLoad((account?.activities || []).filter(a => new Date(a.createdAt || 0).getTime() > Date.now() - 90 * 86400000));
    const qStats = [];
    if (load?.acwr != null) qStats.push({ label: "ACWR", value: load.acwr.toFixed(2) });
    if (load?.acuteLoad7d != null) qStats.push({ label: "7d Load", value: load.acuteLoad7d });
    if (load?.chronicLoad28d != null) qStats.push({ label: "28d Avg", value: load.chronicLoad28d });
    if (readiness.components?.consistency != null) qStats.push({ label: "Konsistenz", value: readiness.components.consistency + "%" });
    quickStats.innerHTML = qStats.map(s => `<div class="quick-stat"><span class="quick-stat-value">${s.value}</span><span class="quick-stat-label">${s.label}</span></div>`).join("");
  }
}

// Dashboard config panel toggle
document.getElementById("dashboard-config-btn")?.addEventListener("click", () => {
  const panel = document.getElementById("dashboard-config-panel");
  if (panel) {
    panel.hidden = !panel.hidden;
    if (!panel.hidden) {
      // Populate checkboxes from config
      const config = getDashboardRingConfig(getCurrentAccount());
      panel.querySelectorAll("input[type=checkbox]").forEach(cb => {
        const ringType = cb.name.replace("ring-", "");
        cb.checked = !!config[ringType];
      });
    }
  }
});

document.getElementById("dashboard-config-save")?.addEventListener("click", () => {
  const panel = document.getElementById("dashboard-config-panel");
  if (!panel) return;
  const config = {};
  panel.querySelectorAll("input[type=checkbox]").forEach(cb => {
    const ringType = cb.name.replace("ring-", "");
    config[ringType] = cb.checked;
  });
  config.readiness = true; // always on
  saveDashboardRingConfig(config);
  panel.hidden = true;
  renderDashboardRings();
});

